  1→<!DOCTYPE html>
  2→<!-- saved from url=(0494)https://xminio.yottastudios.com/xaffine/cb2a1d7f-e53a-4d60-a436-60eae52907de/3oyrir_3fBuKTfhtCfkgc8ZhxbSDlIXYunAZ0fUPua0.html?X-Amz-Algorithm=AWS4-HMAC-SHA256&X-Amz-Content-Sha256=UNSIGNED-PAYLOAD&X-Amz-Credential=N7TSddmz6BawDsf5CLGk%2F20260413%2Fauto%2Fs3%2Faws4_request&X-Amz-Date=20260413T000000Z&X-Amz-Expires=604800&X-Amz-Signature=7bf573c645aba280f7a3467a74dc846991d19d27ce8676347197d1b7f29c1b53&X-Amz-SignedHeaders=host&response-cache-control=public%2C%20max-age%3D604800&x-id=GetObject -->
  3→<html lang="zh-CN"><head><meta http-equiv="Content-Type" content="text/html; charset=UTF-8">
  4→
  5→<title>CollabSpace · 空间站公告</title>
  6→<style>
  7→* { box-sizing: border-box; margin: 0; padding: 0; }
  8→body { font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Microsoft YaHei', sans-serif; background: #f4f5f7; color: #1e293b; font-size: 14px; }
  9→
 10→.page { max-width: 800px; margin: 0 auto; padding: 36px 24px 80px; }
 11→
 12→/* ===== PAGE HEADER ===== */
 13→.page-header { display: flex; align-items: flex-start; justify-content: space-between; margin-bottom: 28px; }
 14→.page-title { font-size: 20px; font-weight: 700; color: #1e293b; }
 15→.page-sub { font-size: 13px; color: #94a3b8; margin-top: 3px; }
 16→
 17→/* ===== SECTION ===== */
 18→.section { background: #fff; border: 1px solid #e2e8f0; border-radius: 12px; margin-bottom: 16px; overflow: hidden; }
 19→.section-header { padding: 14px 20px; border-bottom: 1px solid #f1f5f9; display: flex; align-items: center; justify-content: space-between; }
 20→.section-title { font-size: 13px; font-weight: 600; color: #475569; display: flex; align-items: center; gap: 7px; }
 21→.dot { width: 7px; height: 7px; border-radius: 50%; flex-shrink: 0; }
 22→.section-body { padding: 20px; }
 23→
 24→/* ===== FORM ===== */
 25→.form-group { margin-bottom: 18px; }
 26→.form-label { display: block; font-size: 12px; font-weight: 600; color: #64748b; margin-bottom: 7px; text-transform: uppercase; letter-spacing: 0.4px; }
 27→.req { color: #ef4444; }
 28→.form-input { width: 100%; padding: 9px 12px; border: 1px solid #e2e8f0; border-radius: 7px; font-size: 14px; color: #1e293b; font-family: inherit; transition: border-color .15s, box-shadow .15s; background: #fff; }
 29→.form-input:focus { outline: none; border-color: #6366f1; box-shadow: 0 0 0 3px rgba(99,102,241,.1); }
 30→.form-input.error { border-color: #ef4444; box-shadow: 0 0 0 3px rgba(239,68,68,.1); }
 31→.char-hint { text-align: right; font-size: 11px; color: #cbd5e1; margin-top: 4px; }
 32→.form-hint { font-size: 12px; color: #94a3b8; margin-top: 5px; }
 33→
 34→/* ===== RTE ===== */
 35→.rte-wrap { border: 1px solid #e2e8f0; border-radius: 7px; overflow: hidden; transition: border-color .15s, box-shadow .15s; }
 36→.rte-wrap:focus-within { border-color: #6366f1; box-shadow: 0 0 0 3px rgba(99,102,241,.1); }
 37→.rte-wrap.error { border-color: #ef4444; box-shadow: 0 0 0 3px rgba(239,68,68,.1); }
 38→.rte-toolbar { display: flex; gap: 1px; padding: 5px 8px; background: #f8fafc; border-bottom: 1px solid #f1f5f9; align-items: center; flex-wrap: wrap; }
 39→.rte-btn { width: 26px; height: 26px; border: none; background: transparent; border-radius: 4px; cursor: pointer; display: flex; align-items: center; justify-content: center; color: #64748b; font-size: 12px; font-weight: 700; font-family: inherit; transition: all .1s; }
 40→.rte-btn:hover { background: #e2e8f0; color: #1e293b; }
 41→.rte-sep { width: 1px; height: 18px; background: #e2e8f0; margin: 0 3px; }
 42→.rte-area { min-height: 120px; max-height: 220px; overflow-y: auto; padding: 11px 13px; font-size: 14px; line-height: 1.7; color: #1e293b; outline: none; }
 43→.rte-area:empty::before { content: attr(data-ph); color: #c4cdd6; }
 44→.rte-area p { margin-bottom: 8px; } .rte-area p:last-child { margin-bottom: 0; }
 45→.rte-area strong { font-weight: 700; } .rte-area ul,.rte-area ol { padding-left: 20px; margin-bottom: 8px; }
 46→
 47→/* ===== OPTIONS ===== */
 48→.options-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; }
 49→.toggle-row { display: flex; align-items: center; gap: 10px; }
 50→.toggle { position: relative; width: 36px; height: 20px; flex-shrink: 0; }
 51→.toggle input { opacity: 0; width: 0; height: 0; }
 52→.tslider { position: absolute; inset: 0; background: #cbd5e1; border-radius: 20px; cursor: pointer; transition: .18s; }
 53→.tslider::before { content:''; position:absolute; width:14px; height:14px; left:3px; top:3px; background:#fff; border-radius:50%; transition:.18s; box-shadow:0 1px 3px rgba(0,0,0,.15); }
 54→input:checked + .tslider { background: #6366f1; }
 55→input:checked + .tslider::before { transform: translateX(16px); }
 56→.toggle-label { font-size: 13px; color: #374151; }
 57→
 58→/* ===== PUBLISH TYPE ===== */
 59→.pub-type { display: flex; background: #f1f5f9; border-radius: 8px; padding: 3px; width: fit-content; gap: 2px; margin-bottom: 12px; }
 60→.pub-type-btn { padding: 5px 16px; border-radius: 6px; border: none; font-size: 13px; font-weight: 500; cursor: pointer; background: transparent; color: #64748b; font-family: inherit; transition: all .15s; }
 61→.pub-type-btn.active { background: #fff; color: #6366f1; box-shadow: 0 1px 4px rgba(0,0,0,.1); }
 62→.scheduled-input-row { display: flex; align-items: center; gap: 10px; }
 63→
 64→/* ===== ACTION BAR ===== */
 65→.action-bar { display: flex; justify-content: space-between; align-items: center; padding-top: 4px; border-top: 1px solid #f1f5f9; margin-top: 4px; }
 66→.action-bar-left { font-size: 12px; color: #94a3b8; }
 67→
 68→/* ===== BUTTONS ===== */
 69→.btn { display: inline-flex; align-items: center; gap: 5px; padding: 8px 18px; border-radius: 7px; border: none; cursor: pointer; font-size: 13px; font-weight: 500; font-family: inherit; transition: all .15s; white-space: nowrap; }
 70→.btn-primary { background: #6366f1; color: #fff; }
 71→.btn-primary:hover { background: #4f46e5; }
 72→.btn-secondary { background: #f1f5f9; color: #475569; border: 1px solid #e2e8f0; }
 73→.btn-secondary:hover { background: #e2e8f0; }
 74→.btn-ghost { background: transparent; color: #64748b; border: 1px solid #e2e8f0; }
 75→.btn-ghost:hover { background: #f8fafc; }
 76→.btn-danger { background: transparent; color: #ef4444; border: 1px solid #fecaca; }
 77→.btn-danger:hover { background: #fef2f2; }
 78→.btn-sm { padding: 5px 12px; font-size: 12px; }
 79→.btn-xs { padding: 3px 10px; font-size: 11px; border-radius: 5px; }
 80→.btn-create { background: #6366f1; color: #fff; padding: 9px 20px; border-radius: 8px; font-size: 14px; }
 81→.btn-create:hover { background: #4f46e5; }
 82→
 83→/* ===== PREVIEW ===== */
 84→.preview-label { font-size: 11px; font-weight: 600; color: #94a3b8; text-transform: uppercase; letter-spacing: .5px; margin-bottom: 10px; }
 85→.preview-banner { background: linear-gradient(90deg,#ede9fe,#e0e7ff); border: 1px solid #c7d2fe; border-radius: 8px; padding: 10px 16px; display: flex; align-items: center; gap: 10px; min-height: 42px; margin-bottom: 16px; }
 86→.preview-banner-icon { color: #6366f1; flex-shrink: 0; }
 87→.preview-banner-text { flex: 1; font-size: 13px; color: #3730a3; font-weight: 500; }
 88→.preview-banner-text.ph { color: #a5b4fc; font-style: italic; }
 89→.preview-banner-actions { display: flex; align-items: center; gap: 8px; flex-shrink: 0; }
 90→.preview-banner-link { color: #6366f1; font-size: 12px; text-decoration: underline; }
 91→.popup-wrap { background: #f1f5f9; border-radius: 8px; padding: 20px; position: relative; display: flex; align-items: center; justify-content: center; min-height: 180px; overflow: hidden; }
 92→.popup-overlay { position: absolute; inset: 0; background: rgba(0,0,0,.25); border-radius: 8px; }
 93→.popup-card { position: relative; z-index: 1; background: #fff; border-radius: 10px; width: 340px; padding: 20px; box-shadow: 0 8px 32px rgba(0,0,0,.18); }
 94→.popup-card-title { font-size: 15px; font-weight: 700; color: #1e293b; margin-bottom: 10px; line-height: 1.4; }
 95→.popup-card-body { font-size: 13px; color: #475569; line-height: 1.7; max-height: 100px; overflow-y: auto; margin-bottom: 14px; }
 96→.popup-card-footer { display: flex; justify-content: flex-end; }
 97→.popup-off { color: #94a3b8; font-size: 13px; text-align: center; padding: 24px 0; }
 98→
 99→/* ===== ACTIVE CARD ===== */
100→.active-card { border: 1.5px solid #c7d2fe; border-radius: 10px; background: #fafbff; padding: 18px 20px; }
101→.active-card-title { font-size: 15px; font-weight: 600; color: #1e293b; margin-bottom: 8px; line-height: 1.4; }
102→.card-meta { display: flex; align-items: center; gap: 8px; flex-wrap: wrap; margin-bottom: 12px; }
103→.card-body-preview { font-size: 13px; color: #64748b; line-height: 1.7; max-height: 60px; overflow: hidden; position: relative; }
104→.card-body-preview::after { content:''; position:absolute; bottom:0; left:0; right:0; height:22px; background: linear-gradient(transparent,#fafbff); }
105→.card-actions { display: flex; gap: 8px; margin-top: 14px; }
106→
107→/* ===== SCHEDULED CARD ===== */
108→.scheduled-card { border: 1.5px solid #fed7aa; border-radius: 10px; background: #fffbf5; padding: 18px 20px; }
109→.scheduled-card-title { font-size: 15px; font-weight: 600; color: #1e293b; margin-bottom: 8px; }
110→
111→/* ===== BADGE ===== */
112→.badge { display: inline-flex; align-items: center; gap: 3px; padding: 2px 8px; border-radius: 20px; font-size: 11px; font-weight: 500; }
113→.badge-active { background: #d1fae5; color: #065f46; }
114→.badge-scheduled { background: #fff7ed; color: #c2410c; border: 1px solid #fed7aa; }
115→.badge-expired { background: #f1f5f9; color: #64748b; }
116→.badge-popup { background: #dbeafe; color: #1e40af; }
117→.badge-expire { background: #fef3c7; color: #92400e; }
118→
119→/* ===== HISTORY ===== */
120→.history-item { display: flex; align-items: center; gap: 12px; padding: 13px 20px; border-bottom: 1px solid #f8fafc; transition: background .1s; cursor: default; }
121→.history-item:last-child { border-bottom: none; }
122→.history-item:hover { background: #fafbfc; }
123→.history-info { flex: 1; min-width: 0; }
124→.history-title { font-size: 13px; font-weight: 500; color: #475569; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
125→.history-meta { font-size: 11px; color: #94a3b8; margin-top: 2px; }
126→.history-actions { display: flex; gap: 4px; flex-shrink: 0; }
127→
128→.empty-tip { text-align: center; padding: 28px 0; color: #94a3b8; font-size: 13px; }
129→
130→/* ===== MODAL ===== */
131→.modal-backdrop { position: fixed; inset: 0; background: rgba(0,0,0,.35); z-index: 1000; display: none; align-items: center; justify-content: center; }
132→.modal-backdrop.show { display: flex; }
133→.modal { background: #fff; border-radius: 12px; width: 400px; box-shadow: 0 20px 60px rgba(0,0,0,.18); }
134→.modal-body { padding: 32px 24px 20px; text-align: center; }
135→.modal-icon { width: 52px; height: 52px; border-radius: 50%; display: flex; align-items: center; justify-content: center; margin: 0 auto 14px; }
136→.modal-title { font-size: 15px; font-weight: 700; color: #1e293b; margin-bottom: 8px; }
137→.modal-desc { font-size: 13px; color: #64748b; line-height: 1.6; }
138→.modal-footer { padding: 16px 24px; border-top: 1px solid #f8fafc; display: flex; gap: 8px; justify-content: center; }
139→
140→/* ===== DIVIDER ===== */
141→hr.div { border: none; border-top: 1px solid #f1f5f9; margin: 16px 0; }
142→
143→/* ===== EDITOR BADGE ===== */
144→.editing-tag { font-size: 11px; font-weight: 600; color: #6366f1; background: #ede9fe; border-radius: 4px; padding: 2px 8px; }
145→</style>
146→</head>
147→<body>
148→<div class="page">
149→
150→  <!-- PAGE HEADER -->
151→  <div class="page-header">
152→    <div>
153→      <div class="page-title">空间站公告</div>
154→      <div class="page-sub">同一时间只允许一条公告生效，展示在空间站顶部横幅</div>
155→    </div>
156→    <button class="btn btn-create" id="createBtn" onclick="startCreate()">
157→      <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
158→      创建公告
159→    </button>
160→  </div>
161→
162→  <!-- ===== 编辑区（默认隐藏）===== -->
163→  <div class="section" id="editorSection" style="display:none;">
164→    <div class="section-header">
165→      <div class="section-title">
166→        <span class="dot" style="background:#6366f1;"></span>
167→        <span id="editorLabel">新建公告</span>
168→      </div>
169→      <span class="editing-tag" id="editingTag" style="display:none;">编辑中</span>
170→    </div>
171→    <div class="section-body">
172→
173→      <div class="form-group">
174→        <label class="form-label">标题 <span class="req">*</span></label>
175→        <input class="form-input" id="inputTitle" placeholder="请输入公告标题" maxlength="100" oninput="onTitleInput()">
176→        <div class="char-hint"><span id="titleCount">0</span> / 100</div>
177→      </div>
178→
179→      <div class="form-group">
180→        <label class="form-label">正文内容 <span class="req">*</span></label>
181→        <div class="rte-wrap" id="rteWrap">
182→          <div class="rte-toolbar">
183→            <button class="rte-btn" title="加粗" onclick="fmt(&#39;bold&#39;)"><b>B</b></button>
184→            <button class="rte-btn" title="斜体" onclick="fmt(&#39;italic&#39;)"><i style="font-style:italic">I</i></button>
185→            <button class="rte-btn" title="下划线" onclick="fmt(&#39;underline&#39;)"><u>U</u></button>
186→            <div class="rte-sep"></div>
187→            <button class="rte-btn" title="有序列表" onclick="fmt(&#39;insertOrderedList&#39;)">1.</button>
188→            <button class="rte-btn" title="无序列表" onclick="fmt(&#39;insertUnorderedList&#39;)">•</button>
189→            <div class="rte-sep"></div>
190→            <button class="rte-btn" title="链接" onclick="insertLink()">🔗</button>
191→            <button class="rte-btn" title="分割线" onclick="fmt(&#39;insertHorizontalRule&#39;)">—</button>
192→            <div class="rte-sep"></div>
193→            <button class="rte-btn" title="清除格式" onclick="fmt(&#39;removeFormat&#39;)" style="font-weight:400;font-size:11px;">Tx</button>
194→          </div>
195→          <div class="rte-area" id="rteContent" contenteditable="true" data-ph="请输入公告正文内容…" oninput="updatePreview()"></div>
196→        </div>
197→      </div>
198→
199→      <div class="options-grid" style="margin-bottom:18px;">
200→        <div>
201→          <label class="form-label">有效期</label>
202→          <input class="form-input" type="date" id="inputExpire">
203→          <div class="form-hint">不填则长期有效，到期自动下线</div>
204→        </div>
205→        <div>
206→          <label class="form-label">弹窗展示</label>
207→          <div class="toggle-row" style="margin-top:9px;">
208→            <label class="toggle">
209→              <input type="checkbox" id="togglePopup" onchange="updatePreview()">
210→              <span class="tslider"></span>
211→            </label>
212→            <span class="toggle-label">进入空间站时弹窗提示成员</span>
213→          </div>
214→        </div>
215→      </div>
216→
217→      <hr class="div">
218→
219→      <!-- 发布方式 -->
220→      <div class="form-group" style="margin-bottom:16px;">
221→        <label class="form-label">发布方式</label>
222→        <div class="pub-type">
223→          <button class="pub-type-btn active" id="pubTypeNow" onclick="setPubType(&#39;now&#39;)">立即发布</button>
224→          <button class="pub-type-btn" id="pubTypeScheduled" onclick="setPubType(&#39;scheduled&#39;)">定时发布</button>
225→        </div>
226→        <div id="scheduledTimeRow" style="display:none;">
227→          <div class="scheduled-input-row">
228→            <input class="form-input" type="datetime-local" id="inputScheduleTime" style="width:240px;">
229→            <span class="form-hint" style="margin:0;">发布后将在此时间自动生效</span>
230→          </div>
231→        </div>
232→      </div>
233→
234→      <div class="action-bar">
235→        <div class="action-bar-left" id="editorHint"></div>
236→        <div style="display:flex;gap:8px;">
237→          <button class="btn btn-ghost btn-sm" onclick="cancelEdit()">取消</button>
238→          <button class="btn btn-primary" id="publishBtn" onclick="handlePublish()">发布公告</button>
239→        </div>
240→      </div>
241→    </div>
242→  </div>
243→
244→  <!-- ===== 预览区（默认隐藏）===== -->
245→  <div class="section" id="previewSection" style="display:none;">
246→    <div class="section-header">
247→      <div class="section-title">
248→        <span class="dot" style="background:#10b981;"></span>
249→        实时预览
250→      </div>
251→    </div>
252→    <div class="section-body">
253→      <div class="preview-label">横幅效果</div>
254→      <div class="preview-banner">
255→        <div class="preview-banner-icon">
256→          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M18 8h1a4 4 0 0 1 0 8h-1"></path><path d="M2 8h16v9a4 4 0 0 1-4 4H6a4 4 0 0 1-4-4V8z"></path><line x1="6" y1="1" x2="6" y2="4"></line><line x1="10" y1="1" x2="10" y2="4"></line><line x1="14" y1="1" x2="14" y2="4"></line></svg>
257→        </div>
258→        <div class="preview-banner-text ph" id="previewBannerText">请在上方输入公告标题…</div>
259→        <div class="preview-banner-actions">
260→          <span class="preview-banner-link">查看详情</span>
261→          <span style="color:#6366f1;font-size:16px;">×</span>
262→        </div>
263→      </div>
264→      <div class="preview-label">弹窗效果</div>
265→      <div id="popupPreviewArea">
266→        <div class="popup-off">开启「弹窗展示」后在此预览</div>
267→      </div>
268→    </div>
269→  </div>
270→
271→  <!-- ===== 待发布（定时）===== -->
272→  <div class="section" id="scheduledSection" style="display:none;">
273→    <div class="section-header">
274→      <div class="section-title">
275→        <span class="dot" style="background:#f59e0b;"></span>
276→        待发布公告
277→      </div>
278→    </div>
279→    <div class="section-body" id="scheduledArea"></div>
280→  </div>
281→
282→  <!-- ===== 当前生效 ===== -->
283→  <div class="section">
284→    <div class="section-header">
285→      <div class="section-title">
286→        <span class="dot" style="background:#10b981;"></span>
287→        当前生效公告
288→      </div>
289→    </div>
290→    <div class="section-body" id="activeArea">
291→    <div class="active-card">
292→      <div class="active-card-title">关于近期空间站文件上传限制调整的说明</div>
293→      <div class="card-meta">
294→        <span class="badge badge-active">● 生效中</span>
295→        <span class="badge badge-popup">弹窗</span>
296→        <span class="badge badge-expire">有效期至 2026-06-30</span>
297→        <span style="font-size:12px;color:#94a3b8;">发布于 2026-04-06 14:30</span>
298→      </div>
299→      <div class="card-body-preview"><p>尊敬的空间站成员，</p><p>由于近期存储资源优化调整，单次文件上传大小限制将从 <strong>200MB</strong> 调整为 <strong>100MB</strong>，多文件批量上传每次最多 <strong>10 个</strong>文件。</p></div>
300→      <div class="card-actions">
301→        <button class="btn btn-secondary btn-sm" onclick="loadEdit(1)">编辑</button>
302→        <button class="btn btn-ghost btn-sm" onclick="openOfflineModal(1)">下线</button>
303→      </div>
304→    </div>
305→  </div>
306→  </div>
307→
308→  <!-- ===== 历史公告 ===== -->
309→  <div class="section">
310→    <div class="section-header">
311→      <div class="section-title">
312→        <span class="dot" style="background:#94a3b8;"></span>
313→        历史公告
314→      </div>
315→    </div>
316→    <div id="historyList">
317→    <div class="history-item">
318→      <div class="history-info">
319→        <div class="history-title">2026 Q2 全员复盘会议时间确认</div>
320→        <div class="history-meta">2026-04-05 10:00 · 有效期至 2026-04-15</div>
321→      </div>
322→      <div class="history-actions">
323→        <button class="btn btn-ghost btn-xs" onclick="loadEditFromHistory(2)">重新发布</button>
324→        <button class="btn btn-ghost btn-xs" style="color:#ef4444;border-color:#fecaca;" onclick="openDeleteModal(2)">删除</button>
325→      </div>
326→    </div>
327→  
328→    <div class="history-item">
329→      <div class="history-info">
330→        <div class="history-title">新功能上线：智能文档支持多人实时协同</div>
331→        <div class="history-meta">2026-04-03 09:15</div>
332→      </div>
333→      <div class="history-actions">
334→        <button class="btn btn-ghost btn-xs" onclick="loadEditFromHistory(3)">重新发布</button>
335→        <button class="btn btn-ghost btn-xs" style="color:#ef4444;border-color:#fecaca;" onclick="openDeleteModal(3)">删除</button>
336→      </div>
337→    </div>
338→  </div>
339→  </div>
340→
341→</div>
342→
343→<!-- ===== 替换确认 ===== -->
344→<div class="modal-backdrop" id="replaceModal">
345→  <div class="modal">
346→    <div class="modal-body">
347→      <div class="modal-icon" style="background:#fff7ed;">
348→        <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#f59e0b" stroke-width="2"><circle cx="12" cy="12" r="10"></circle><line x1="12" y1="8" x2="12" y2="12"></line><line x1="12" y1="16" x2="12.01" y2="16"></line></svg>
349→      </div>
350→      <div class="modal-title">当前已有生效公告</div>
351→      <div class="modal-desc">「<span id="replacingTitle"></span>」正在生效，<br>发布后将自动下线旧公告，确认继续？</div>
352→    </div>
353→    <div class="modal-footer">
354→      <button class="btn btn-secondary" onclick="closeModal(&#39;replaceModal&#39;)">取消</button>
355→      <button class="btn btn-primary" onclick="confirmReplace()">确认发布</button>
356→    </div>
357→  </div>
358→</div>
359→
360→<!-- ===== 下线确认 ===== -->
361→<div class="modal-backdrop" id="offlineModal">
362→  <div class="modal">
363→    <div class="modal-body">
364→      <div class="modal-icon" style="background:#eff6ff;">
365→        <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#3b82f6" stroke-width="2"><circle cx="12" cy="12" r="10"></circle><polyline points="8 12 12 16 16 12"></polyline><line x1="12" y1="8" x2="12" y2="16"></line></svg>
366→      </div>
367→      <div class="modal-title">确认下线公告？</div>
368→      <div class="modal-desc">下线后成员侧横幅将立即消失，<br>公告将进入历史列表，可重新发布。</div>
369→    </div>
370→    <div class="modal-footer">
371→      <button class="btn btn-secondary" onclick="closeModal(&#39;offlineModal&#39;)">取消</button>
372→      <button class="btn btn-primary" onclick="confirmOffline()">确认下线</button>
373→    </div>
374→  </div>
375→</div>
376→
377→<!-- ===== 删除确认 ===== -->
378→<div class="modal-backdrop" id="deleteModal">
379→  <div class="modal">
380→    <div class="modal-body">
381→      <div class="modal-icon" style="background:#fef2f2;">
382→        <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#ef4444" stroke-width="2"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2"></path></svg>
383→      </div>
384→      <div class="modal-title">确认删除公告？</div>
385→      <div class="modal-desc">删除后不可恢复。</div>
386→    </div>
387→    <div class="modal-footer">
388→      <button class="btn btn-secondary" onclick="closeModal(&#39;deleteModal&#39;)">取消</button>
389→      <button class="btn btn-danger" onclick="confirmDelete()">确认删除</button>
390→    </div>
391→  </div>
392→</div>
393→
394→<script>
395→// ===== DATA =====
396→let announcements = [
397→  {
398→    id: 1,
399→    title: '关于近期空间站文件上传限制调整的说明',
400→    content: '<p>尊敬的空间站成员，</p><p>由于近期存储资源优化调整，单次文件上传大小限制将从 <strong>200MB</strong> 调整为 <strong>100MB</strong>，多文件批量上传每次最多 <strong>10 个</strong>文件。</p>',
401→    time: '2026-04-06 14:30', expire: '2026-06-30', popup: true, status: 'active', scheduledAt: null
402→  },
403→  {
404→    id: 2,
405→    title: '2026 Q2 全员复盘会议时间确认',
406→    content: '<p>Q2 全员复盘会定于 <strong>4 月 15 日（周三）14:00</strong> 举行，请提前准备复盘材料。</p>',
407→    time: '2026-04-05 10:00', expire: '2026-04-15', popup: false, status: 'expired', scheduledAt: null
408→  },
409→  {
410→    id: 3,
411→    title: '新功能上线：智能文档支持多人实时协同',
412→    content: '<p>🎉 CollabSpace 智能文档现已支持多人实时协同编辑，最多支持 <strong>50 人</strong>同时在线。欢迎体验！</p>',
413→    time: '2026-04-03 09:15', expire: null, popup: false, status: 'expired', scheduledAt: null
414→  }
415→];
416→
417→let editingId = null;      // 正在编辑的公告id（null=新建）
418→let offlineId = null;
419→let deletingId = null;
420→let pendingReplace = null; // { cb } 替换确认后执行的回调
421→let pubType = 'now';       // 'now' | 'scheduled'
422→
423→// ===== INIT =====
424→renderAll();
425→
426→function renderAll() {
427→  renderScheduled();
428→  renderActive();
429→  renderHistory();
430→}
431→
432→// ===== SCHEDULED =====
433→function renderScheduled() {
434→  const list = announcements.filter(a => a.status === 'scheduled');
435→  const sec = document.getElementById('scheduledSection');
436→  const area = document.getElementById('scheduledArea');
437→  if (list.length === 0) { sec.style.display = 'none'; return; }
438→  sec.style.display = '';
439→  area.innerHTML = list.map(a => `
440→    <div class="scheduled-card">
441→      <div class="scheduled-card-title">${esc(a.title)}</div>
442→      <div class="card-meta">
443→        <span class="badge badge-scheduled">⏰ 定时发布</span>
444→        <span style="font-size:12px;color:#64748b;">计划生效：${a.scheduledAt}</span>
445→        ${a.expire ? `<span class="badge badge-expire">有效期至 ${a.expire}</span>` : ''}
446→        ${a.popup ? '<span class="badge badge-popup">弹窗</span>' : ''}
447→      </div>
448→      <div class="card-body-preview" style="background:#fffbf5;">${a.content}</div>
449→      <div class="card-actions">
450→        <button class="btn btn-secondary btn-sm" onclick="cancelScheduled(${a.id})">取消发布并重新编辑</button>
451→        <button class="btn btn-danger btn-sm" onclick="openDeleteModal(${a.id})">删除</button>
452→      </div>
453→    </div>
454→  `).join('');
455→}
456→
457→// ===== ACTIVE =====
458→function renderActive() {
459→  const a = announcements.find(x => x.status === 'active');
460→  const el = document.getElementById('activeArea');
461→  if (!a) { el.innerHTML = '<div class="empty-tip">暂无生效公告</div>'; return; }
462→  el.innerHTML = `
463→    <div class="active-card">
464→      <div class="active-card-title">${esc(a.title)}</div>
465→      <div class="card-meta">
466→        <span class="badge badge-active">● 生效中</span>
467→        ${a.popup ? '<span class="badge badge-popup">弹窗</span>' : ''}
468→        ${a.expire ? `<span class="badge badge-expire">有效期至 ${a.expire}</span>` : '<span style="font-size:12px;color:#94a3b8;">长期有效</span>'}
469→        <span style="font-size:12px;color:#94a3b8;">发布于 ${a.time}</span>
470→      </div>
471→      <div class="card-body-preview">${a.content}</div>
472→      <div class="card-actions">
473→        <button class="btn btn-secondary btn-sm" onclick="loadEdit(${a.id})">编辑</button>
474→        <button class="btn btn-ghost btn-sm" onclick="openOfflineModal(${a.id})">下线</button>
475→      </div>
476→    </div>
477→  `;
478→}
479→
480→// ===== HISTORY =====
481→function renderHistory() {
482→  const list = announcements.filter(x => x.status === 'expired');
483→  const el = document.getElementById('historyList');
484→  if (list.length === 0) { el.innerHTML = '<div class="empty-tip">暂无历史公告</div>'; return; }
485→  el.innerHTML = list.map(a => `
486→    <div class="history-item">
487→      <div class="history-info">
488→        <div class="history-title">${esc(a.title)}</div>
489→        <div class="history-meta">${a.time}${a.expire ? ' · 有效期至 '+a.expire : ''}</div>
490→      </div>
491→      <div class="history-actions">
492→        <button class="btn btn-ghost btn-xs" onclick="loadEditFromHistory(${a.id})">重新发布</button>
493→        <button class="btn btn-ghost btn-xs" style="color:#ef4444;border-color:#fecaca;" onclick="openDeleteModal(${a.id})">删除</button>
494→      </div>
495→    </div>
496→  `).join('');
497→}
498→
499→// ===== EDITOR OPEN/CLOSE =====
500→function showEditor() {
501→  document.getElementById('editorSection').style.display = '';
502→  document.getElementById('previewSection').style.display = '';
503→  document.getElementById('createBtn').style.display = 'none';
504→}
505→
506→function hideEditor() {
507→  document.getElementById('editorSection').style.display = 'none';
508→  document.getElementById('previewSection').style.display = 'none';
509→  document.getElementById('createBtn').style.display = '';
510→}
511→
512→function startCreate() {
513→  editingId = null;
514→  clearForm();
515→  document.getElementById('editorLabel').textContent = '新建公告';
516→  document.getElementById('editingTag').style.display = 'none';
517→  document.getElementById('editorHint').textContent = '';
518→  document.getElementById('publishBtn').textContent = '发布公告';
519→  setPubType('now');
520→  showEditor();
521→  window.scrollTo({ top: 0, behavior: 'smooth' });
522→}
523→
524→function loadEdit(id) {
525→  const a = announcements.find(x => x.id === id);
526→  if (!a) return;
527→  editingId = id;
528→  fillForm(a);
529→  document.getElementById('editorLabel').textContent = '编辑公告';
530→  document.getElementById('editingTag').style.display = '';
531→  document.getElementById('editorHint').textContent = '修改后点击保存将更新当前生效公告';
532→  document.getElementById('publishBtn').textContent = '保存修改';
533→  setPubType('now');
534→  showEditor();
535→  window.scrollTo({ top: 0, behavior: 'smooth' });
536→}
537→
538→function loadEditFromHistory(id) {
539→  const a = announcements.find(x => x.id === id);
540→  if (!a) return;
541→  editingId = null; // 历史发布视为新建，保留原记录
542→  fillForm(a);
543→  document.getElementById('editorLabel').textContent = '重新发布';
544→  document.getElementById('editingTag').style.display = 'none';
545→  document.getElementById('editorHint').textContent = '将基于历史内容创建一条新公告';
546→  document.getElementById('publishBtn').textContent = '发布公告';
547→  setPubType('now');
548→  showEditor();
549→  window.scrollTo({ top: 0, behavior: 'smooth' });
550→}
551→
552→function cancelScheduled(id) {
553→  const a = announcements.find(x => x.id === id);
554→  if (!a) return;
555→  editingId = null;
556→  fillForm(a);
557→  a.status = 'expired'; // 暂存为历史（取消后不自动删除，保留记录）
558→  announcements = announcements.filter(x => x.id !== id); // 从列表移除定时记录
559→  document.getElementById('editorLabel').textContent = '重新编辑';
560→  document.getElementById('editingTag').style.display = 'none';
561→  document.getElementById('editorHint').textContent = '已取消定时发布，请重新配置后发布';
562→  document.getElementById('publishBtn').textContent = '发布公告';
563→  setPubType('now');
564→  showEditor();
565→  renderAll();
566→  window.scrollTo({ top: 0, behavior: 'smooth' });
567→}
568→
569→function cancelEdit() {
570→  editingId = null;
571→  clearForm();
572→  setPubType('now');
573→  hideEditor();
574→}
575→
576→// ===== FORM HELPERS =====
577→function clearForm() {
578→  document.getElementById('inputTitle').value = '';
579→  document.getElementById('titleCount').textContent = '0';
580→  document.getElementById('rteContent').innerHTML = '';
581→  document.getElementById('inputExpire').value = '';
582→  document.getElementById('togglePopup').checked = false;
583→  document.getElementById('inputScheduleTime').value = '';
584→  updatePreview();
585→}
586→
587→function fillForm(a) {
588→  document.getElementById('inputTitle').value = a.title;
589→  document.getElementById('titleCount').textContent = a.title.length;
590→  document.getElementById('rteContent').innerHTML = a.content;
591→  document.getElementById('inputExpire').value = a.expire || '';
592→  document.getElementById('togglePopup').checked = a.popup;
593→  document.getElementById('inputScheduleTime').value = '';
594→  updatePreview();
595→}
596→
597→// ===== PUB TYPE =====
598→function setPubType(type) {
599→  pubType = type;
600→  document.getElementById('pubTypeNow').classList.toggle('active', type === 'now');
601→  document.getElementById('pubTypeScheduled').classList.toggle('active', type === 'scheduled');
602→  document.getElementById('scheduledTimeRow').style.display = type === 'scheduled' ? '' : 'none';
603→  document.getElementById('publishBtn').textContent =
604→    type === 'scheduled' ? '定时发布' : (editingId ? '保存修改' : '发布公告');
605→}
606→
607→// ===== PUBLISH =====
608→function handlePublish() {
609→  const title = document.getElementById('inputTitle').value.trim();
610→  const content = document.getElementById('rteContent').innerHTML.trim();
611→  if (!title) { flashError('inputTitle'); return; }
612→  if (!content) { flashError('rteWrap'); return; }
613→  if (pubType === 'scheduled') {
614→    const t = document.getElementById('inputScheduleTime').value;
615→    if (!t) { flashError('inputScheduleTime'); return; }
616→  }
617→
618→  // 编辑已有的直接保存，不需要替换确认
619→  if (editingId) { doSave(); return; }
620→
621→  const existing = announcements.find(a => a.status === 'active');
622→  if (existing && pubType === 'now') {
623→    pendingReplace = { cb: doSave };
624→    document.getElementById('replacingTitle').textContent =
625→      existing.title.length > 22 ? existing.title.slice(0,22)+'…' : existing.title;
626→    document.getElementById('replaceModal').classList.add('show');
627→  } else {
628→    doSave();
629→  }
630→}
631→
632→function confirmReplace() {
633→  const existing = announcements.find(a => a.status === 'active');
634→  if (existing) existing.status = 'expired';
635→  closeModal('replaceModal');
636→  if (pendingReplace?.cb) pendingReplace.cb();
637→  pendingReplace = null;
638→}
639→
640→function doSave() {
641→  const title = document.getElementById('inputTitle').value.trim();
642→  const content = document.getElementById('rteContent').innerHTML.trim();
643→  const expire = document.getElementById('inputExpire').value || null;
644→  const popup = document.getElementById('togglePopup').checked;
645→  const isScheduled = pubType === 'scheduled';
646→  const scheduledAt = isScheduled ? document.getElementById('inputScheduleTime').value.replace('T',' ') : null;
647→
648→  if (editingId) {
649→    const a = announcements.find(x => x.id === editingId);
650→    if (a) Object.assign(a, { title, content, expire, popup, time: nowStr() });
651→  } else {
652→    announcements.unshift({
653→      id: Date.now(), title, content, expire, popup,
654→      status: isScheduled ? 'scheduled' : 'active',
655→      scheduledAt, time: nowStr()
656→    });
657→  }
658→  cancelEdit();
659→  renderAll();
660→}
661→
662→// ===== OFFLINE =====
663→function openOfflineModal(id) {
664→  offlineId = id;
665→  document.getElementById('offlineModal').classList.add('show');
666→}
667→function confirmOffline() {
668→  const a = announcements.find(x => x.id === offlineId);
669→  if (a) a.status = 'expired';
670→  closeModal('offlineModal');
671→  renderAll();
672→}
673→
674→// ===== DELETE =====
675→function openDeleteModal(id) {
676→  deletingId = id;
677→  document.getElementById('deleteModal').classList.add('show');
678→}
679→function confirmDelete() {
680→  announcements = announcements.filter(a => a.id !== deletingId);
681→  if (editingId === deletingId) cancelEdit();
682→  closeModal('deleteModal');
683→  renderAll();
684→}
685→
686→// ===== PREVIEW =====
687→function onTitleInput() {
688→  document.getElementById('titleCount').textContent = document.getElementById('inputTitle').value.length;
689→  updatePreview();
690→}
691→
692→function updatePreview() {
693→  const title = document.getElementById('inputTitle').value.trim();
694→  const popup = document.getElementById('togglePopup').checked;
695→  const content = document.getElementById('rteContent').innerHTML;
696→
697→  const bt = document.getElementById('previewBannerText');
698→  if (title) { bt.textContent = title; bt.classList.remove('ph'); }
699→  else { bt.textContent = '请在上方输入公告标题…'; bt.classList.add('ph'); }
700→
701→  const pa = document.getElementById('popupPreviewArea');
702→  if (popup) {
703→    pa.innerHTML = `
704→      <div class="popup-wrap">
705→        <div class="popup-overlay"></div>
706→        <div class="popup-card">
707→          <div class="popup-card-title">${esc(title) || '<span style="color:#c4cdd6;font-style:italic;font-weight:400;">公告标题</span>'}</div>
708→          <div class="popup-card-body">${content || '<span style="color:#c4cdd6;font-style:italic;">公告正文…</span>'}</div>
709→          <div class="popup-card-footer"><button class="btn btn-primary btn-sm">我知道了</button></div>
710→        </div>
711→      </div>`;
712→  } else {
713→    pa.innerHTML = '<div class="popup-off">开启「弹窗展示」后在此预览</div>';
714→  }
715→}
716→
717→// ===== RTE =====
718→function fmt(cmd) { document.execCommand(cmd, false, null); document.getElementById('rteContent').focus(); updatePreview(); }
719→function insertLink() {
720→  const url = prompt('请输入链接地址：');
721→  if (url) document.execCommand('createLink', false, url);
722→  document.getElementById('rteContent').focus(); updatePreview();
723→}
724→
725→// ===== UTILS =====
726→function closeModal(id) { document.getElementById(id).classList.remove('show'); }
727→function esc(s) { return (s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
728→function nowStr() {
729→  const d = new Date();
730→  return `${d.getFullYear()}-${p(d.getMonth()+1)}-${p(d.getDate())} ${p(d.getHours())}:${p(d.getMinutes())}`;
731→}
732→function p(n) { return n<10?'0'+n:String(n); }
733→function flashError(id) {
734→  const el = document.getElementById(id);
735→  el.classList.add('error');
736→  setTimeout(() => el.classList.remove('error'), 1800);
737→}
738→document.querySelectorAll('.modal-backdrop').forEach(el => {
739→  el.addEventListener('click', e => { if (e.target === el) closeModal(el.id); });
740→});
741→</script>
742→
743→
744→</body></html>

