import { Alert } from 'antd';
import classNames from 'classnames';
import React from 'react';

import { isPrivate } from '@/common/constants';
import { t } from '@/i18n';

import styles from './collabDriveAlert.module.css';

interface ICollabDriveAlertProps {
  className?: string;
}
let dismiss = !!sessionStorage.getItem('collabDriveAlertHidden');
export const CollabDriveAlert: React.FC<ICollabDriveAlertProps> = ({ className }) => {
  if (dismiss) return null;
  return (
    <Alert
      showIcon={false}
      type="info"
      title={(
        <div className={styles.collabDriveAlertMarquee}>
          <div
            className={styles.collabDriveAlertContent}
            dangerouslySetInnerHTML={{
              __html: t('collabDriveAlert', {
                url: isPrivate
                  ? 'https://xcollabspace-private.yottastudios.com/#/share/shrafxXxZDBxr?mode=page'
                  : 'https://xcollabspace.yottastudios.com/#/share/shrafHfhEG3pW?mode=page',
              }),
            }}
          />
          <div
            className={styles.collabDriveAlertContent}
            dangerouslySetInnerHTML={{
              __html: t('collabDriveAlert', {
                url: isPrivate
                  ? 'https://xcollabspace-private.yottastudios.com/#/share/shrafxXxZDBxr?mode=page'
                  : 'https://xcollabspace.yottastudios.com/#/share/shrafHfhEG3pW?mode=page',
              }),
            }}
          />
        </div>
      )}
      className={classNames(styles.collabDriveAlert, className)}
      closable={{
        onClose: () => {
          sessionStorage.setItem('collabDriveAlertHidden', 'true');
          dismiss = true;
        },
        closeIcon: true,
      }}
      banner
    />
  );
};

