// 公告守卫
import { useRequest } from 'ahooks';
import { Modal } from 'antd';
import { useState } from 'react';

import { getLatestAnnouncement } from '@/common/api/announce.ts';
import { t } from '@/i18n';
import { isAioWsMessageType, useAioWsEvent } from '@/store/query/ws';

export const AnnounceGuard = () => {
  const [open, setOpen] = useState(false);
  const { data, run } = useRequest(getLatestAnnouncement, {
    onSuccess({ autoPopout }) {
      setOpen(autoPopout);
    },
  });
  useAioWsEvent((msg) => {
    if (isAioWsMessageType(msg, 'ADD_ANNOUNCEMENT')) {
      run();
    }
  });
  return (
    <Modal
      footer={null}
      title={(
        <span className="text-primary">
          {t('collabSpaceUpgradeAnnouncement')}
        </span>
      )}
      open={open}
      destroyOnHidden
      width={450}
      onCancel={() => {
        setOpen(false);
      }}
      cancelButtonProps={{ hidden: true }}
      onOk={() => {
        setOpen(false);
      }}
    >
      {
        data?.content && <div className="max-h-[500px] overflow-auto" dangerouslySetInnerHTML={{ __html: data.content }} />
      }
    </Modal>
  );
};

