import { useRequest } from 'ahooks';
import { Modal, Timeline } from 'antd';
import { type FC, memo, type Ref, useImperativeHandle, useState } from 'react';

import { getPublishedAnnouncement } from '@/common/api/announce.ts';
import { TipTapEditor } from '@/components/Common/TiptapEditor/TipTapEditor.tsx';
import { useInView } from '@/hooks/useInView.ts';
import { t } from '@/i18n';
export type IAnnouncementDrawerInstance = {
  show(): void;
};
export const AnnouncementDrawerBase: FC<{
  ref?: Ref<IAnnouncementDrawerInstance>;
  loaded?(): void;
}> = ({
  ref, loaded,
}) => {
  const [open, setOpen] = useState(false);
  const { refresh, data } = useRequest(getPublishedAnnouncement, {
    pollingInterval: 10 * 60 * 1000,
    ready: open,
    refreshDeps: [open],
    onSuccess() {
      loaded?.();
    },
  });
  // const [announces] = useState<IAnnouncementItem[]>([]);
  useImperativeHandle(ref, () => {
    return {
      show() {
        refresh();
        setOpen(true);
      },
    };
  });

  const [el] = useState<null | HTMLDivElement>(null);
  const [inView] = useInView(el);
  useRequest(() => {
    return Promise.resolve();
  }, {
    refreshDeps: [inView],
    ready: inView,
    debounceWait: 100,
  });
  return (
    <Modal
      footer={null}
      title={(
        <span className="text-primary">
          {t('collabSpaceUpgradeAnnouncement')}
        </span>
      )}
      width={1000}
      open={open}
      mask={{ closable: false }}
      onCancel={() => {
        setOpen(false);
      }}
      destroyOnHidden
    >
      <Timeline
        className="max-h-[600px] overflow-auto py-4"
        mode="left"
        items={data?.map((o) => {
          return {
            children: (
              <div key={o.announceId}>
                <div>
                  {o.publishTime}
                </div>
                <TipTapEditor className="!border-0 max-h" editable={false} value={o.content} />
              </div>
            ),
          };
        })}
      />
      {/* <div ref={(e) => setEl(e)} className="text-center text-color-text-secondary"> */}
      {/*  <LoadingOutlined className="mr-2 text-primary" /> */}
      {/*  <I18nText>loading</I18nText> */}
      {/* </div> */}
    </Modal>
  );
};
export const AnnouncementDrawer = memo(AnnouncementDrawerBase);

