import { Button, DatePicker, Dropdown, Modal } from 'antd';
import dayjs from 'dayjs';
import type { FC, PropsWithChildren, Ref } from 'react';
import { memo, useCallback, useImperativeHandle, useState } from 'react';

import { toAnnounce } from '@/common/dataConversion/announce.ts';
import { I18nText } from '@/components/Common/I18nText/I18nText.tsx';
import { TipTapEditor } from '@/components/Common/TiptapEditor/TipTapEditor.tsx';
import type { IEditorTool } from '@/components/Common/TiptapEditor/type';
import { FontColor } from '@/components/icon/FontColor';
import { t } from '@/i18n';
import type { IAnnouncementItem } from '@/types/announcement.ts';

export type IModifyAnnounceInstance = {
  show(v?: IAnnouncementItem): void;
  close(): void;
};

const ModifyAnnouncementBase: FC<PropsWithChildren<{
  onOk?(v: IAnnouncementItem): void;
  confirmLoading?: boolean;
  ref?: Ref<IModifyAnnounceInstance>;
}>> = ({
  children, ref, confirmLoading, onOk,
}) => {
  const [open, setOpen] = useState(false);
  const [inEditingData, setInEditingData] = useState<IAnnouncementItem>(() => toAnnounce());
  useImperativeHandle(ref, () => {
    return {
      close() {
        setOpen(false);
      },
      show(v) {
        setInEditingData(v
          ? v
          : toAnnounce());
        setOpen(true);
      },
    };
  });

  // 移除knock不支持的文字样式，文字颜色只支持黑（重置）红绿
  const modifyEditorTools = useCallback<NonNullable<Parameters<typeof TipTapEditor>[0]['modifyTools']>>((tools, { editor }) => {
    const result: IEditorTool[] = [];
    for (const tool of tools) {
      if (tool.name === 'textBg' || tool.name === 'underline') {
        continue;
      }
      if (tool.name === 'fontColor') {
        const { color } = editor.getAttributes('textStyle');
        result.push({
          name: 'fontColor',
          node: (
            <Dropdown
              trigger={['click']}
              menu={{
                items: [
                  {
                    key: 'unset',
                    label: <>{t('reset')}</>,
                  },
                  {
                    key: '#dd191d',
                    label: <span style={{ color: '#dd191d' }}>{t('red')}</span>,
                  },
                  {
                    key: '#3ca51e',
                    label: <span style={{ color: '#3ca51e' }}>{t('green')}</span>,
                  },
                ],
                onClick: ({ key }) => {
                  if (key === 'unset') {
                    editor.commands.unsetColor();
                  } else {
                    editor.commands.setColor(key);
                  }
                },
              }}
            >
              <Button
                size="small"
                icon={<FontColor style={{ color }} className="text-[16px]" />}
                variant={color ? 'filled' : 'text'}
                color={color ? 'primary' : 'default'}
              />
            </Dropdown>
          ),
        });
        continue;
      }
      result.push(tool);
    }
    return result;
  }, []);
  return (
    <>
      <Modal
        mask={{ closable: false }}
        onCancel={() => setOpen(false)}
        open={open}
        destroyOnHidden
        width={650}
        onOk={() => onOk?.(inEditingData)}
        confirmLoading={confirmLoading}
        title={<I18nText>upgradeConfig</I18nText>}
      >
        <div className="mb-2">
          <span className="mr-4">
            <I18nText>publishTime</I18nText>
          </span>
          <DatePicker
            format="YYYY-MM-DD HH:mm"
            showTime={{
              format: 'HH:mm',
              showSecond: false,
            }}
            value={inEditingData.publishTime ? dayjs(inEditingData.publishTime) : undefined}
            onChange={(_e, date) => {
              setInEditingData({
                ...inEditingData,
                publishTime: date as string,
              });
            }}
          />
        </div>
        <div className="mb-1">
          <I18nText>announceContent</I18nText>
        </div>
        <TipTapEditor
          value={inEditingData.content}
          onChange={(e) => {
            setInEditingData({
              ...inEditingData,
              content: e,
            });
          }}
          modifyTools={modifyEditorTools}
          editable
          className="max-h-[450px] mb-2"
        />
      </Modal>
      <span onClick={() => setOpen(true)}>
        {children}
      </span>

    </>
  );
};
export const ModifyAnnouncement = memo(ModifyAnnouncementBase);

