import { I18nText } from '@/components/Common/I18nText/I18nText.tsx';
import { StaticTree, StaticTreeItem } from '@/components/StaticTree/StaticTree.tsx';
import { t } from '@/i18n';
import { AppCenter } from '@/icon';
import { MigrationControl } from '@/pages/user-backend/migration-control/MigrationControl.tsx';
import { RoutePath, useAioRoute } from '@/routes';
import { useGetUserInfoQuery } from '@/store/query/user';

import { AdminFeedback } from './admin-feedback/AdminFeedback';
import { ApplicationCenter } from './application-center/ApplicationCenter';
import { DocMigration } from './doc-migration/DocMigration';
import styles from './index.module.css';
import SpaceRoles from './space-roles';
import { SpaceTeam } from './space-team/SpaceTeam';
import { DataBoard } from './super-admin-tools/data-board';
import { UpgradeAnnouncement } from './upgrade-announcement/UpgradeAnnouncement';

const navLinkClassName = (p: { isActive: boolean }) => {
  return classNames('select-none px-2 py-1 rounded w-full inline-block !text-gray-50 transition hover:bg-white/5', p.isActive && '!bg-white/10');
};

const feedbackVisibleUsers = [
  'fusu@yottastudios.com',
  'jinghe@yottastudios.com',
  'yangming@yottastudios.com',
  'jingyan@yottastudios.com',
];

const UserBackend: React.FC = () => {
  const { data: user } = useGetUserInfoQuery();
  const { navTo } = useAioRoute();
  return (
    <div className={styles.layout}>
      <aside className={classNames(styles.aside, 'bg-aside-bg')}>
        <header className={styles.logo}>
          <img src="/static/img/collabspace.png" style={{ height: 32 }} />
          <div>{t('spaceMgtBackend')}</div>
        </header>
        <StaticTree className="pl-2 pr-4" defaultExpandAll>
          <StaticTreeItem
            dataKey="/user-backend/space-roles"
            label={(
              <NavLink
                className={navLinkClassName}
                to="../space-roles"
              >
                <I18nText>spacePermissionManagement</I18nText>
              </NavLink>
            )}
          />
          <StaticTreeItem
            dataKey="/user-backend/space-doc-migration"
            label={(
              <NavLink
                className={navLinkClassName}
                to="../space-doc-migration"
              >
                <I18nText>spaceDocMove</I18nText>
              </NavLink>
            )}
          />
          {
            (isDev || (user && superAdminEmails.includes(user.email))) && (
              <StaticTreeItem
                dataKey="/user-backend/admin-tools"
                label={(
                  <NavLink
                    className={navLinkClassName}
                    to="../admin-tools"
                  >
                    <I18nText>superAdminTool</I18nText>
                  </NavLink>
                )}
              >
                <StaticTreeItem
                  dataKey="/user-backend/admin-tools/upgrade-announcement"
                  label={(
                    <NavLink
                      className={navLinkClassName}
                      to="../admin-tools/upgrade-announcement"
                    >
                      <I18nText>configUpgradeNotice</I18nText>
                    </NavLink>
                  )}
                />
                <StaticTreeItem
                  dataKey="/user-backend/admin-tools/data-board"
                  label={(
                    <NavLink
                      className={navLinkClassName}
                      to="../admin-tools/data-board"
                    >
                      <I18nText>spaceAndMemberUsage</I18nText>
                    </NavLink>
                  )}
                />
                {
                  (isDev || (user && feedbackVisibleUsers.includes(user.email))) && (
                    <StaticTreeItem
                      dataKey="/user-backend/admin-tools/feedback"
                      label={(
                        <NavLink
                          className={navLinkClassName}
                          to="../admin-tools/feedback"
                        >
                          <I18nText>feedbackCollection</I18nText>
                        </NavLink>
                      )}
                    />
                  )
                }
                <StaticTreeItem
                  dataKey="/user-backend/admin-tools/application-center"
                  label={(
                    <NavLink
                      className={navLinkClassName}
                      to="../admin-tools/application-center"
                    >
                      <I18nText>applicationCenter</I18nText>
                    </NavLink>
                  )}
                />
              </StaticTreeItem>
            )
          }

        </StaticTree>
      </aside>
      <main className={classNames(styles.main, 'flex flex-col')}>
        <header className={styles.header}>
          <Link to="/aio">
            <Button color="primary" variant="outlined">{t('returnCollabspace')}</Button>
          </Link>
          <Flex align="center" gap={24}>
            <MigrationControl />
            <Button
              size="small"
              type="text"
              shape="circle"
              icon={<AppCenter className="text-[20px] !text-color-text-tertiary" />}
              onClick={() => {
                navTo(RoutePath.AppCenter);
              }}
            />
            <AioUserSetting>
              <AioUserAvatar />
            </AioUserSetting>
          </Flex>
        </header>
        <main className="aio-layout-content-container flex-1">
          <Routes>
            <Route index element={<Navigate to="space-roles" />} />
            <Route path="space-roles" element={<SpaceRoles />} />
            <Route path="space-doc-migration" element={<DocMigration />} />
            <Route path="space-team" element={<SpaceTeam />} />
            <Route path="admin-tools">
              <Route index element={<Navigate to="upgrade-announcement" />} />
              <Route path="upgrade-announcement" element={<UpgradeAnnouncement />} />
              {(isDev || (user && feedbackVisibleUsers.includes(user?.email))) && <Route path="feedback" element={<AdminFeedback />} />}
              {(isDev || (user && superAdminEmails.includes(user.email))) && (
                <Route path="data-board" element={<DataBoard />} />
              )}
              <Route path="application-center" element={<ApplicationCenter />} />
            </Route>
          </Routes>
        </main>
      </main>
    </div>
  );
};
export default UserBackend;

