package com.yottastudios.ns.collabspace.announcement.manager.impl;

import com.baomidou.mybatisplus.core.conditions.query.QueryWrapper;
import com.yottastudios.ns.collabspace.announcement.entity.AnnouncementReadRecordEntity;
import com.yottastudios.ns.collabspace.announcement.manager.AnnouncementReadRecordManager;
import com.yottastudios.ns.collabspace.announcement.mapper.AnnouncementReadRecordMapper;
import jakarta.annotation.Resource;
import org.springframework.stereotype.Service;

import java.util.List;


@Service
public class AnnounceReadRecordManagerImpl implements AnnouncementReadRecordManager {
    @Resource
    private AnnouncementReadRecordMapper announcementReadRecordMapper;

    @Override
    public AnnouncementReadRecordEntity selectByAnnouncementIdAndUserId(Long id, Long userId) {
        QueryWrapper<AnnouncementReadRecordEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().eq(AnnouncementReadRecordEntity::getAnnouncementId, id)
                .eq(AnnouncementReadRecordEntity::getUserId, userId)
                .eq(AnnouncementReadRecordEntity::getIsDeleted, 0);
        List<AnnouncementReadRecordEntity> list = announcementReadRecordMapper.selectList(queryWrapper);
        return list != null  && !list.isEmpty() ? list.getFirst() : null;
    }
}

