package com.yottastudios.ns.collabspace.spaceannouncement.service.impl;

import com.yottastudios.ns.collabspace.control.infrastructure.ControlTemplate;
import com.yottastudios.ns.collabspace.core.exception.BusinessException;
import com.yottastudios.ns.collabspace.grpc.impl.ApitableGrpcClientServiceImpl;
import com.yottastudios.ns.collabspace.shared.config.QueueConfig;
import com.yottastudios.ns.collabspace.shared.context.SessionContext;
import com.yottastudios.ns.collabspace.shared.mq.RabbitMqSender;
import com.yottastudios.ns.collabspace.spaceannouncement.entity.SpaceAnnouncementEntity;
import com.yottastudios.ns.collabspace.spaceannouncement.enums.AnnouncementCategory;
import com.yottastudios.ns.collabspace.spaceannouncement.enums.PublishType;
import com.yottastudios.ns.collabspace.spaceannouncement.enums.SpaceAnnouncementStatus;
import com.yottastudios.ns.collabspace.spaceannouncement.manager.SpaceAnnouncementManager;
import com.yottastudios.ns.collabspace.spaceannouncement.manager.SpaceAnnouncementReadRecordManager;
import com.yottastudios.ns.collabspace.spaceannouncement.ro.CreateSpaceAnnouncementRo;
import com.yottastudios.ns.collabspace.spaceannouncement.ro.UpdateSpaceAnnouncementRo;
import com.yottastudios.ns.collabspace.spaceannouncement.vo.ActiveAnnouncementVo;
import com.yottastudios.ns.collabspace.spaceannouncement.vo.SpaceAnnouncementVo;
import com.yottastudios.ns.collabspace.spaceannouncement.vo.UnreadPopupAnnouncementVo;
import com.yottastudios.ns.collabspace.space.enums.SpaceException;
import com.yottastudios.ns.collabspace.user.vo.UserSimpleInfoVo;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.amqp.core.Message;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.Duration;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.Collections;
import java.util.List;

@Slf4j
@Service
public class SpaceAnnouncementServiceImpl implements ISpaceAnnouncementService {

    private static final DateTimeFormatter DATETIME_FORMAT = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm");

    @Resource
    private SpaceAnnouncementManager announcementManager;

    @Resource
    private SpaceAnnouncementReadRecordManager readRecordManager;

    @Resource
    private ControlTemplate controlTemplate;

    @Resource
    private ApitableGrpcClientServiceImpl apitableGrpcClientService;

    @Resource
    private RabbitMqSender rabbitMqSender;

    @Override
    @Transactional(rollbackFor = Exception.class)
    public SpaceAnnouncementVo createAnnouncement(CreateSpaceAnnouncementRo ro) {
        Long userId = SessionContext.getUserId();
        // 空间站公告需要校验管理员权限
        if (AnnouncementCategory.SPACE.getCode() == ro.getCategory()) {
            if (ro.getSpaceId() == null || ro.getSpaceId().isBlank()) {
                throw new BusinessException(SpaceException.UNAUTHORIZED);
            }
            controlTemplate.mustBeSpaceAdmin(userId, ro.getSpaceId());
        }

        // 获取发布人信息
        UserSimpleInfoVo userInfo = apitableGrpcClientService.getUserById(userId);
        String publisherName = userInfo != null ? userInfo.getNickName() : "";

        // 构建实体
        SpaceAnnouncementEntity entity = new SpaceAnnouncementEntity();
        entity.setSpaceId(ro.getSpaceId());
        entity.setCategory(ro.getCategory());
        entity.setTitle(ro.getTitle());
        entity.setContent(ro.getContent());
        entity.setIsPopup(ro.getIsPopup());
        entity.setPublishType(ro.getPublishType());
        entity.setPublisherId(userId);
        entity.setPublisherName(publisherName);

        boolean isScheduled = PublishType.SCHEDULED.getCode() == ro.getPublishType();

        if (isScheduled) {
            LocalDateTime scheduledTime = LocalDateTime.parse(ro.getScheduledPublishTime(), DATETIME_FORMAT);
            entity.setScheduledPublishTime(scheduledTime);
            entity.setStatus(SpaceAnnouncementStatus.PENDING.getCode());
        } else {
            // 立即发布：将同类型旧公告下线
            offlineCurrentActive(ro.getCategory(), ro.getSpaceId());
            entity.setStatus(SpaceAnnouncementStatus.ACTIVE.getCode());
            entity.setPublishTime(LocalDateTime.now());
        }

        // 有效期
        if (ro.getExpireTime() != null && !ro.getExpireTime().isBlank()) {
            entity.setExpireTime(LocalDateTime.parse(ro.getExpireTime(), DATETIME_FORMAT));
        }

        announcementManager.insert(entity);
        log.info("[SpaceAnnouncement] 公告创建成功, id={}, category={}, publishType={}",
                entity.getId(), ro.getCategory(), ro.getPublishType());

        // 定时发布：发送延迟消息
        if (isScheduled) {
            sendDelayedMessage(entity.getId(), entity.getScheduledPublishTime());
        }

        return toVo(entity);
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public void updateAnnouncement(UpdateSpaceAnnouncementRo ro) {
        SpaceAnnouncementEntity entity = announcementManager.getById(ro.getId());
        if (entity == null) {
            throw new BusinessException(SpaceException.UNAUTHORIZED);
        }
        if (SpaceAnnouncementStatus.ACTIVE.getCode() != entity.getStatus()) {
            throw new BusinessException(SpaceException.UNAUTHORIZED);
        }

        // 权限校验
        Long userId = SessionContext.getUserId();
        if (AnnouncementCategory.SPACE.getCode() == entity.getCategory()) {
            controlTemplate.mustBeSpaceAdmin(userId, entity.getSpaceId());
        }

        entity.setTitle(ro.getTitle());
        entity.setContent(ro.getContent());
        entity.setIsPopup(ro.getIsPopup());
        entity.setPublishTime(LocalDateTime.now());

        if (ro.getExpireTime() != null && !ro.getExpireTime().isBlank()) {
            entity.setExpireTime(LocalDateTime.parse(ro.getExpireTime(), DATETIME_FORMAT));
        } else {
            entity.setExpireTime(null);
        }

        announcementManager.updateById(entity);

        // 清空已读记录，弹窗重新生效
        readRecordManager.deleteByAnnouncementId(entity.getId());
        log.info("[SpaceAnnouncement] 公告编辑成功, id={}, 已清空已读记录", entity.getId());
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public void offlineAnnouncement(Long id) {
        SpaceAnnouncementEntity entity = announcementManager.getById(id);
        if (entity == null) return;

        Long userId = SessionContext.getUserId();
        if (AnnouncementCategory.SPACE.getCode() == entity.getCategory()) {
            controlTemplate.mustBeSpaceAdmin(userId, entity.getSpaceId());
        }

        entity.setStatus(SpaceAnnouncementStatus.OFFLINE.getCode());
        entity.setOfflineTime(LocalDateTime.now());
        announcementManager.updateById(entity);
        log.info("[SpaceAnnouncement] 公告下线, id={}", id);
    }

    @Override
    public void deleteAnnouncement(Long id) {
        SpaceAnnouncementEntity entity = announcementManager.getById(id);
        if (entity == null) return;
        if (SpaceAnnouncementStatus.OFFLINE.getCode() != entity.getStatus()) {
            throw new BusinessException(SpaceException.UNAUTHORIZED);
        }

        Long userId = SessionContext.getUserId();
        if (AnnouncementCategory.SPACE.getCode() == entity.getCategory()) {
            controlTemplate.mustBeSpaceAdmin(userId, entity.getSpaceId());
        }

        entity.setIsDeleted(1);
        announcementManager.updateById(entity);
        log.info("[SpaceAnnouncement] 公告软删除, id={}", id);
    }

    @Override
    public SpaceAnnouncementVo getActiveAnnouncement(Integer category, String spaceId) {
        SpaceAnnouncementEntity entity = announcementManager.getActiveAnnouncement(category, spaceId);
        return entity != null ? toVo(entity) : null;
    }

    @Override
    public List<SpaceAnnouncementVo> getPendingAnnouncements(Integer category, String spaceId) {
        return announcementManager.getPendingAnnouncements(category, spaceId).stream()
                .map(this::toVo).toList();
    }

    @Override
    public List<SpaceAnnouncementVo> getOfflineAnnouncements(Integer category, String spaceId) {
        return announcementManager.getOfflineAnnouncements(category, spaceId).stream()
                .map(this::toVo).toList();
    }

    @Override
    public List<ActiveAnnouncementVo> getBannerAnnouncements(String spaceId) {
        List<SpaceAnnouncementEntity> list = announcementManager.getActiveBannerAnnouncements(spaceId);
        return list.stream().map(e -> ActiveAnnouncementVo.builder()
                .id(e.getId())
                .category(e.getCategory())
                .title(e.getTitle())
                .build()).toList();
    }

    @Override
    public SpaceAnnouncementVo getAnnouncementDetail(Long id) {
        SpaceAnnouncementEntity entity = announcementManager.getById(id);
        if (entity == null) return null;

        // 写已读记录
        Long userId = SessionContext.getUserId();
        readRecordManager.addReadRecord(entity.getId(), userId, entity.getSpaceId());

        return toVo(entity);
    }

    @Override
    public List<UnreadPopupAnnouncementVo> getUnreadPopupAnnouncements(String spaceId) {
        Long userId = SessionContext.getUserId();
        List<SpaceAnnouncementEntity> activeList = announcementManager.getActiveBannerAnnouncements(spaceId);

        // 只保留 is_popup=true 的
        List<SpaceAnnouncementEntity> popupList = activeList.stream()
                .filter(e -> Boolean.TRUE.equals(e.getIsPopup()))
                .toList();
        if (popupList.isEmpty()) return Collections.emptyList();

        // 过滤已读
        List<Long> announcementIds = popupList.stream().map(SpaceAnnouncementEntity::getId).toList();
        List<Long> readIds = readRecordManager.getReadAnnouncementIds(userId, announcementIds);

        // 返回未读的，平台公告在前(category=2)，空间站在后(category=1)
        return popupList.stream()
                .filter(e -> !readIds.contains(e.getId()))
                .map(e -> UnreadPopupAnnouncementVo.builder()
                        .id(e.getId())
                        .category(e.getCategory())
                        .title(e.getTitle())
                        .content(e.getContent())
                        .build())
                .toList();
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public void activateScheduledAnnouncement(Long announcementId) {
        SpaceAnnouncementEntity entity = announcementManager.getById(announcementId);
        if (entity == null || SpaceAnnouncementStatus.PENDING.getCode() != entity.getStatus()) {
            log.info("[SpaceAnnouncement] 定时发布跳过, id={}, 状态不是PENDING", announcementId);
            return;
        }

        // 下线同类型旧公告
        offlineCurrentActive(entity.getCategory(), entity.getSpaceId());

        entity.setStatus(SpaceAnnouncementStatus.ACTIVE.getCode());
        entity.setPublishTime(LocalDateTime.now());
        announcementManager.updateById(entity);
        log.info("[SpaceAnnouncement] 定时发布生效, id={}", announcementId);
    }

    @Override
    public void expireAnnouncements() {
        List<SpaceAnnouncementEntity> expiredList = announcementManager.getExpiredActiveAnnouncements();
        if (expiredList.isEmpty()) return;

        List<Long> ids = expiredList.stream().map(SpaceAnnouncementEntity::getId).toList();
        announcementManager.batchOffline(ids);
        log.info("[SpaceAnnouncement] 到期自动下线 {} 条公告, ids={}", ids.size(), ids);
    }

    // ── private helpers ──

    private void offlineCurrentActive(Integer category, String spaceId) {
        SpaceAnnouncementEntity existing = announcementManager.getActiveAnnouncement(category, spaceId);
        if (existing != null) {
            existing.setStatus(SpaceAnnouncementStatus.OFFLINE.getCode());
            existing.setOfflineTime(LocalDateTime.now());
            announcementManager.updateById(existing);
            log.info("[SpaceAnnouncement] 旧公告自动下线, id={}", existing.getId());
        }
    }

    private void sendDelayedMessage(Long announcementId, LocalDateTime scheduledTime) {
        long delay = Duration.between(LocalDateTime.now(), scheduledTime).toMillis();
        if (delay < 0) delay = 0;
        Message message = new Message(announcementId.toString().getBytes());
        rabbitMqSender.sendDelayedMessage(
                QueueConfig.SPACE_ANNOUNCEMENT_EXCHANGE,
                QueueConfig.SPACE_ANNOUNCEMENT_KEY,
                message, delay);
        log.info("[SpaceAnnouncement] 延迟消息已发送, id={}, delay={}ms", announcementId, delay);
    }

    private SpaceAnnouncementVo toVo(SpaceAnnouncementEntity entity) {
        return SpaceAnnouncementVo.builder()
                .id(entity.getId())
                .spaceId(entity.getSpaceId())
                .category(entity.getCategory())
                .title(entity.getTitle())
                .content(entity.getContent())
                .status(entity.getStatus())
                .publishType(entity.getPublishType())
                .isPopup(entity.getIsPopup())
                .scheduledPublishTime(entity.getScheduledPublishTime())
                .publishTime(entity.getPublishTime())
                .expireTime(entity.getExpireTime())
                .offlineTime(entity.getOfflineTime())
                .publisherId(entity.getPublisherId())
                .publisherName(entity.getPublisherName())
                .createdAt(entity.getCreatedAt())
                .build();
    }
}
