735→        wrapper.eq(SpaceAnnouncementEntity::getStatus, SpaceAnnouncementStatus.ACTIVE.getCode())
736→               .eq(SpaceAnnouncementEntity::getCategory, category);
737→        if (AnnouncementCategory.SPACE.getCode() == category) {
738→            wrapper.eq(SpaceAnnouncementEntity::getSpaceId, spaceId);
739→        }
740→        wrapper.orderByDesc(SpaceAnnouncementEntity::getPublishTime)
741→               .last("LIMIT 1");
742→        return spaceAnnouncementMapper.selectOne(wrapper);
743→    }
