748→        wrapper.eq(SpaceAnnouncementEntity::getStatus, SpaceAnnouncementStatus.PENDING.getCode())
749→               .eq(SpaceAnnouncementEntity::getCategory, category);
750→        if (AnnouncementCategory.SPACE.getCode() == category) {
751→            wrapper.eq(SpaceAnnouncementEntity::getSpaceId, spaceId);
752→        }
