761→               .eq(SpaceAnnouncementEntity::getCategory, category);
762→        if (AnnouncementCategory.SPACE.getCode() == category) {
763→            wrapper.eq(SpaceAnnouncementEntity::getSpaceId, spaceId);
764→        }
