773→               .and(w -> w.eq(SpaceAnnouncementEntity::getCategory, AnnouncementCategory.PLATFORM.getCode())
774→                          .or(nested -> nested.eq(SpaceAnnouncementEntity::getCategory, AnnouncementCategory.SPACE.getCode())
775→                                              .eq(SpaceAnnouncementEntity::getSpaceId, spaceId)));
776→        wrapper.orderByDesc(SpaceAnnouncementEntity::getCategory);
