import org.springframework.stereotype.Service;

import java.time.LocalDateTime;
import java.util.Collections;
import java.util.List;

@Service
public class SpaceAnnouncementReadRecordManagerImpl implements SpaceAnnouncementReadRecordManager {

    @Resource
    private SpaceAnnouncementReadRecordMapper readRecordMapper;

    @Override
    public boolean hasRead(Long announcementId, Long userId) {
        LambdaQueryWrapper<SpaceAnnouncementReadRecordEntity> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(SpaceAnnouncementReadRecordEntity::getAnnouncementId, announcementId)
               .eq(SpaceAnnouncementReadRecordEntity::getUserId, userId);
        return readRecordMapper.selectCount(wrapper) > 0;
    }

    @Override
    public void addReadRecord(Long announcementId, Long userId, String spaceId) {
        if (hasRead(announcementId, userId)) return;
        SpaceAnnouncementReadRecordEntity record = SpaceAnnouncementReadRecordEntity.builder()
                .announcementId(announcementId)
                .userId(userId)
                .spaceId(spaceId)
                .createdAt(LocalDateTime.now())
                .build();
        readRecordMapper.insert(record);
    }

    @Override
    public void deleteByAnnouncementId(Long announcementId) {
        LambdaQueryWrapper<SpaceAnnouncementReadRecordEntity> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(SpaceAnnouncementReadRecordEntity::getAnnouncementId, announcementId);
        readRecordMapper.delete(wrapper);
    }

    @Override
    public List<Long> getReadAnnouncementIds(Long userId, List<Long> announcementIds) {
        if (announcementIds == null || announcementIds.isEmpty()) return Collections.emptyList();
        LambdaQueryWrapper<SpaceAnnouncementReadRecordEntity> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(SpaceAnnouncementReadRecordEntity::getUserId, userId)
               .in(SpaceAnnouncementReadRecordEntity::getAnnouncementId, announcementIds)
               .select(SpaceAnnouncementReadRecordEntity::getAnnouncementId);
        return readRecordMapper.selectList(wrapper).stream()
                .map(SpaceAnnouncementReadRecordEntity::getAnnouncementId)
                .toList();
    }
}
