289→    private void sendDelayedMessage(Long announcementId, LocalDateTime scheduledTime) {
290→        long delay = Duration.between(LocalDateTime.now(), scheduledTime).toMillis();
291→        if (delay < 0) delay = 0;
292→        // RabbitMqSender.sendDelayedMessage takes Object, pass String directly
293→        rabbitMqSender.sendDelayedMessage(
294→                QueueConfig.SPACE_ANNOUNCEMENT_EXCHANGE,
295→                QueueConfig.SPACE_ANNOUNCEMENT_KEY,
296→                announcementId.toString(), delay);
297→        log.info("[SpaceAnnouncement] 延迟消息已发送, id={}, delay={}ms", announcementId, delay);
298→    }
