304→                .category(entity.getCategory())
305→                .title(entity.getTitle())
306→                .content(entity.getContent())
307→                .status(entity.getStatus())
308→                .publishType(entity.getPublishType())
309→                .isPopup(entity.getIsPopup())
310→                .scheduledPublishTime(entity.getScheduledPublishTime())
311→                .publishTime(entity.getPublishTime())
312→                .expireTime(entity.getExpireTime())
313→                .offlineTime(entity.getOfflineTime())
314→                .publisherId(entity.getPublisherId())
315→                .publisherName(entity.getPublisherName())
316→                .createdAt(entity.getCreatedAt())
317→                .build();
318→    }
