  1→package com.yottastudios.ns.collabspace.spaceannouncement.manager.impl;
  2→
  3→import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
  4→import com.baomidou.mybatisplus.core.conditions.update.LambdaUpdateWrapper;
  5→import com.yottastudios.ns.collabspace.spaceannouncement.entity.SpaceAnnouncementEntity;
  6→import com.yottastudios.ns.collabspace.spaceannouncement.enums.AnnouncementCategory;
  7→import com.yottastudios.ns.collabspace.spaceannouncement.enums.SpaceAnnouncementStatus;
  8→import com.yottastudios.ns.collabspace.spaceannouncement.manager.SpaceAnnouncementManager;
  9→import com.yottastudios.ns.collabspace.spaceannouncement.mapper.SpaceAnnouncementMapper;
 10→import jakarta.annotation.Resource;
 11→import org.springframework.stereotype.Service;
 12→
 13→import java.time.LocalDateTime;
 14→import java.util.List;
 15→
 16→@Service
 17→public class SpaceAnnouncementManagerImpl implements SpaceAnnouncementManager {
 18→
 19→    @Resource
 20→    private SpaceAnnouncementMapper spaceAnnouncementMapper;
 21→
 22→    @Override
 23→    public SpaceAnnouncementEntity getById(Long id) {
 24→        return spaceAnnouncementMapper.selectById(id);
 25→    }
 26→
 27→    @Override
 28→    public void insert(SpaceAnnouncementEntity entity) {
 29→        spaceAnnouncementMapper.insert(entity);
 30→    }
 31→
 32→    @Override
 33→    public void updateById(SpaceAnnouncementEntity entity) {
 34→        spaceAnnouncementMapper.updateById(entity);
 35→    }
 36→
 37→    @Override
 38→    public SpaceAnnouncementEntity getActiveAnnouncement(Integer category, String spaceId) {
 39→        LambdaQueryWrapper<SpaceAnnouncementEntity> wrapper = new LambdaQueryWrapper<>();
 40→        wrapper.eq(SpaceAnnouncementEntity::getStatus, SpaceAnnouncementStatus.ACTIVE.getCode())
 41→               .eq(SpaceAnnouncementEntity::getCategory, category);
 42→        if (AnnouncementCategory.SPACE.getCode() == category) {
 43→            wrapper.eq(SpaceAnnouncementEntity::getSpaceId, spaceId);
 44→        }
 45→        wrapper.orderByDesc(SpaceAnnouncementEntity::getPublishTime)
 46→               .last("LIMIT 1");
 47→        return spaceAnnouncementMapper.selectOne(wrapper);
 48→    }
 49→
 50→    @Override
 51→    public List<SpaceAnnouncementEntity> getPendingAnnouncements(Integer category, String spaceId) {
 52→        LambdaQueryWrapper<SpaceAnnouncementEntity> wrapper = new LambdaQueryWrapper<>();
 53→        wrapper.eq(SpaceAnnouncementEntity::getStatus, SpaceAnnouncementStatus.PENDING.getCode())
 54→               .eq(SpaceAnnouncementEntity::getCategory, category);
 55→        if (AnnouncementCategory.SPACE.getCode() == category) {
 56→            wrapper.eq(SpaceAnnouncementEntity::getSpaceId, spaceId);
 57→        }
 58→        wrapper.orderByDesc(SpaceAnnouncementEntity::getScheduledPublishTime);
 59→        return spaceAnnouncementMapper.selectList(wrapper);
 60→    }
 61→
 62→    @Override
 63→    public List<SpaceAnnouncementEntity> getOfflineAnnouncements(Integer category, String spaceId) {
 64→        LambdaQueryWrapper<SpaceAnnouncementEntity> wrapper = new LambdaQueryWrapper<>();
 65→        wrapper.eq(SpaceAnnouncementEntity::getStatus, SpaceAnnouncementStatus.OFFLINE.getCode())
 66→               .eq(SpaceAnnouncementEntity::getCategory, category);
 67→        if (AnnouncementCategory.SPACE.getCode() == category) {
 68→            wrapper.eq(SpaceAnnouncementEntity::getSpaceId, spaceId);
 69→        }
 70→        wrapper.orderByDesc(SpaceAnnouncementEntity::getPublishTime);
 71→        return spaceAnnouncementMapper.selectList(wrapper);
 72→    }
 73→
 74→    @Override
 75→    public List<SpaceAnnouncementEntity> getActiveBannerAnnouncements(String spaceId) {
 76→        LambdaQueryWrapper<SpaceAnnouncementEntity> wrapper = new LambdaQueryWrapper<>();
 77→        wrapper.eq(SpaceAnnouncementEntity::getStatus, SpaceAnnouncementStatus.ACTIVE.getCode())
 78→               .and(w -> w.eq(SpaceAnnouncementEntity::getCategory, AnnouncementCategory.PLATFORM.getCode())
 79→                          .or(nested -> nested.eq(SpaceAnnouncementEntity::getCategory, AnnouncementCategory.SPACE.getCode())
 80→                                              .eq(SpaceAnnouncementEntity::getSpaceId, spaceId)));
 81→        wrapper.orderByDesc(SpaceAnnouncementEntity::getCategory);
 82→        return spaceAnnouncementMapper.selectList(wrapper);
 83→    }
 84→
 85→    @Override
 86→    public List<SpaceAnnouncementEntity> getExpiredActiveAnnouncements() {
 87→        LambdaQueryWrapper<SpaceAnnouncementEntity> wrapper = new LambdaQueryWrapper<>();
 88→        wrapper.eq(SpaceAnnouncementEntity::getStatus, SpaceAnnouncementStatus.ACTIVE.getCode())
 89→               .isNotNull(SpaceAnnouncementEntity::getExpireTime)
 90→               .le(SpaceAnnouncementEntity::getExpireTime, LocalDateTime.now());
 91→        return spaceAnnouncementMapper.selectList(wrapper);
 92→    }
 93→
 94→    @Override
