package com.yottastudios.ns.collabspace.spaceannouncement.manager.impl;

import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import com.baomidou.mybatisplus.core.conditions.update.LambdaUpdateWrapper;
import com.yottastudios.ns.collabspace.spaceannouncement.entity.SpaceAnnouncementEntity;
import com.yottastudios.ns.collabspace.spaceannouncement.enums.AnnouncementCategory;
import com.yottastudios.ns.collabspace.spaceannouncement.enums.SpaceAnnouncementStatus;
import com.yottastudios.ns.collabspace.spaceannouncement.manager.SpaceAnnouncementManager;
import com.yottastudios.ns.collabspace.spaceannouncement.mapper.SpaceAnnouncementMapper;
import jakarta.annotation.Resource;
import org.springframework.stereotype.Service;

import java.time.LocalDateTime;
import java.util.List;

@Service
public class SpaceAnnouncementManagerImpl implements SpaceAnnouncementManager {

    @Resource
    private SpaceAnnouncementMapper spaceAnnouncementMapper;

    @Override
    public SpaceAnnouncementEntity getById(Long id) {
        return spaceAnnouncementMapper.selectById(id);
    }

    @Override
    public void insert(SpaceAnnouncementEntity entity) {
        spaceAnnouncementMapper.insert(entity);
    }

    @Override
    public void updateById(SpaceAnnouncementEntity entity) {
        spaceAnnouncementMapper.updateById(entity);
    }

    @Override
    public SpaceAnnouncementEntity getActiveAnnouncement(Integer category, String spaceId) {
        LambdaQueryWrapper<SpaceAnnouncementEntity> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(SpaceAnnouncementEntity::getStatus, SpaceAnnouncementStatus.ACTIVE.getCode())
               .eq(SpaceAnnouncementEntity::getCategory, category);
        if (AnnouncementCategory.SPACE.getCode() == category) {
            wrapper.eq(SpaceAnnouncementEntity::getSpaceId, spaceId);
        }
        wrapper.orderByDesc(SpaceAnnouncementEntity::getPublishTime)
               .last("LIMIT 1");
        return spaceAnnouncementMapper.selectOne(wrapper);
    }

    @Override
    public List<SpaceAnnouncementEntity> getPendingAnnouncements(Integer category, String spaceId) {
        LambdaQueryWrapper<SpaceAnnouncementEntity> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(SpaceAnnouncementEntity::getStatus, SpaceAnnouncementStatus.PENDING.getCode())
               .eq(SpaceAnnouncementEntity::getCategory, category);
        if (AnnouncementCategory.SPACE.getCode() == category) {
            wrapper.eq(SpaceAnnouncementEntity::getSpaceId, spaceId);
        }
        wrapper.orderByDesc(SpaceAnnouncementEntity::getScheduledPublishTime);
        return spaceAnnouncementMapper.selectList(wrapper);
    }

    @Override
    public List<SpaceAnnouncementEntity> getOfflineAnnouncements(Integer category, String spaceId) {
        LambdaQueryWrapper<SpaceAnnouncementEntity> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(SpaceAnnouncementEntity::getStatus, SpaceAnnouncementStatus.OFFLINE.getCode())
               .eq(SpaceAnnouncementEntity::getCategory, category);
        if (AnnouncementCategory.SPACE.getCode() == category) {
            wrapper.eq(SpaceAnnouncementEntity::getSpaceId, spaceId);
        }
        wrapper.orderByDesc(SpaceAnnouncementEntity::getPublishTime);
        return spaceAnnouncementMapper.selectList(wrapper);
    }

    @Override
    public List<SpaceAnnouncementEntity> getActiveBannerAnnouncements(String spaceId) {
        LambdaQueryWrapper<SpaceAnnouncementEntity> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(SpaceAnnouncementEntity::getStatus, SpaceAnnouncementStatus.ACTIVE.getCode())
               .and(w -> w.eq(SpaceAnnouncementEntity::getCategory, AnnouncementCategory.PLATFORM.getCode())
                          .or(nested -> nested.eq(SpaceAnnouncementEntity::getCategory, AnnouncementCategory.SPACE.getCode())
                                              .eq(SpaceAnnouncementEntity::getSpaceId, spaceId)));
        wrapper.orderByDesc(SpaceAnnouncementEntity::getCategory);
        return spaceAnnouncementMapper.selectList(wrapper);
    }

    @Override
    public List<SpaceAnnouncementEntity> getExpiredActiveAnnouncements() {
        LambdaQueryWrapper<SpaceAnnouncementEntity> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(SpaceAnnouncementEntity::getStatus, SpaceAnnouncementStatus.ACTIVE.getCode())
               .isNotNull(SpaceAnnouncementEntity::getExpireTime)
               .le(SpaceAnnouncementEntity::getExpireTime, LocalDateTime.now());
        return spaceAnnouncementMapper.selectList(wrapper);
    }

    @Override
    public void batchOffline(List<Long> ids) {
        if (ids == null || ids.isEmpty()) return;
        LambdaUpdateWrapper<SpaceAnnouncementEntity> wrapper = new LambdaUpdateWrapper<>();
        wrapper.in(SpaceAnnouncementEntity::getId, ids)
               .set(SpaceAnnouncementEntity::getStatus, SpaceAnnouncementStatus.OFFLINE.getCode())
               .set(SpaceAnnouncementEntity::getOfflineTime, LocalDateTime.now());
        spaceAnnouncementMapper.update(null, wrapper);
    }
}

