    await test_§1_权限校验();
    await test_§2_编辑公告();
    await test_§3_有效期();
    await test_§4_弹窗();
    await test_§5_发布机制();
    await test_§6_生效管理();
    await test_§7_历史管理();
    await test_§8_横幅();
    await test_§9_详情();

    // 维度补充测试
    await test_参数校验();
    await test_注入防护();
    await test_多账号补充();
    await test_异常数据();
    await test_并发();
    await test_响应结构();
    await test_重复检测();
    await test_错误码();
    await test_未登录();

    // 清理
    restoreSession('admin');
    await cleanup();
  } catch (e) {
    if (e.cause?.code === 'ECONNREFUSED') {
      console.log('\n❌ 无法连接测试环境，请检查网络');
    } else {
      console.log(`\n❌ 异常: ${e.stack || e.message}`);
    }
    // 尝试清理
    try {
      restoreSession('admin');
      await cleanup();
    } catch (_) {}
    process.exit(1);
  }

  console.log(`\n=============================`);
  console.log(`✅ 通过: ${passed}  ❌ 失败: ${failed}  📊 总计: ${passed + failed}`);
  console.log(`=============================`);
  process.exit(failed > 0 ? 1 : 0);
}

main();

