/**
 * 2210-空间站公告功能 - 接口测试脚本
 *
 * 用法: node test-api.js
 * 要求: Node.js 18+（原生 fetch）
 * 自动登录测试环境，无需手动填 Cookie
 *
 * 接口清单（10 个）：
 *   POST /space-announcement/create    — 创建/发布公告
 *   POST /space-announcement/update    — 编辑当前生效公告
 *   POST /space-announcement/offline   — 下线公告
 *   POST /space-announcement/delete    — 删除历史公告（软删除）
 *   GET  /space-announcement/active    — 获取当前生效公告
 *   GET  /space-announcement/pending   — 获取待发布公告列表
 *   GET  /space-announcement/history   — 获取历史公告列表
 *   GET  /space-announcement/banner    — 获取横幅公告（用户端）
 *   GET  /space-announcement/detail    — 获取公告详情（同时记录已读）
 *   GET  /space-announcement/unread-popup — 获取未读弹窗公告
 */

// ========== 配置 ==========
const CONFIG = {
  host: 'http://xcollabspace-test.xtool-staging.yottastudios.com',
  adminEmail: 'admin@yottastudios.com',       // 空间站管理员
  normalEmail: 'test2@yottastudios.com',       // 普通成员（非管理员）
  spaceId: 'spcQB8z3iXMF0',                   // nanbei 测试空间站
};

// ========== 测试框架 ==========
let passed = 0;
let failed = 0;
let cookie = '';
let xsrfToken = '';

function assert(name, condition, detail) {
  if (condition) {
    console.log(`  ✅ ${name}`);
    passed++;
  } else {
    console.log(`  ❌ ${name}`);
    if (detail !== undefined)
      console.log(`     实际值:`, typeof detail === 'object'
        ? JSON.stringify(detail).slice(0, 300) : detail);
    failed++;
  }
}

// ========== HTTP 工具 ==========
function parseCookies(res) {
  const cookies = {};
  const setCookieHeaders = res.headers.getSetCookie?.() || [];
  for (const header of setCookieHeaders) {
    const [kv] = header.split(';');
    const [k, v] = kv.split('=');
    cookies[k.trim()] = v.trim();
  }
  return cookies;
}

async function rawFetch(method, url, body) {
  const headers = {
    'x-space-id': CONFIG.spaceId,
    'content-type': 'application/json',
  };
  if (cookie) headers['cookie'] = cookie;
  if (xsrfToken) headers['x-xsrf-token'] = xsrfToken;

  const opts = { method, headers, redirect: 'manual' };
  if (body) opts.body = JSON.stringify(body);
  return fetch(url, opts);
}

async function GET(path) {
  const res = await rawFetch('GET', `${CONFIG.host}/api/v1${path}`);
  return res.json();
}

async function POST(path, body) {
  const res = await rawFetch('POST', `${CONFIG.host}/api/v1${path}`, body);
  return res.json();
}

// ========== 登录管理 ==========
async function login() {
  console.log(`🔑 登录 ${CONFIG.adminEmail} ...`);
  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${CONFIG.adminEmail}`,
    { redirect: 'manual' });
  const cookies = parseCookies(res);
  if (!cookies.SESSION) {
    console.log('❌ 登录失败');
    process.exit(1);
  }
  xsrfToken = cookies['XSRF-TOKEN'] || '';
  cookie = `SESSION=${cookies.SESSION}; XSRF-TOKEN=${xsrfToken}`;
  console.log(`   ✅ 登录成功\n`);
}

let savedSessions = {};
function saveSession(name) {
  savedSessions[name] = { cookie, xsrfToken };
}
function restoreSession(name) {
  ({ cookie, xsrfToken } = savedSessions[name]);
}

async function loginAs(email) {
  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${encodeURIComponent(email)}`,
    { redirect: 'manual' });
  const cookies = parseCookies(res);
  if (!cookies.SESSION) {
    console.log(`  ⚠️  登录 ${email} 失败，跳过`);
    return false;
  }
  xsrfToken = cookies['XSRF-TOKEN'] || '';
  cookie = `SESSION=${cookies.SESSION}; XSRF-TOKEN=${xsrfToken}`;
  return true;
}

// ========== 辅助函数 ==========
function futureTime(minutesFromNow) {
  const d = new Date(Date.now() + minutesFromNow * 60 * 1000);
  const pad = n => String(n).padStart(2, '0');
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}`;
}

function makeCreateRo(overrides = {}) {
  return {
    category: 1,
    spaceId: CONFIG.spaceId,
    title: `测试公告-${Date.now()}`,
    content: '<p>测试正文内容</p>',
    isPopup: false,
    publishType: 0,
    ...overrides,
  };
}

/** 创建一条公告并返回 id，失败返回 null */
async function createAndGetId(overrides = {}) {
  const res = await POST('/space-announcement/create', makeCreateRo(overrides));
  return res.success ? String(res.data?.id) : null;
}

/** 下线公告 */
async function offlineById(id) {
  await POST(`/space-announcement/offline?id=${id}`);
}

/** 软删除公告 */
async function deleteById(id) {
  await POST(`/space-announcement/delete?id=${id}`);
}

/** 完整清理：下线 → 删除 */
async function cleanupAnnouncement(id) {
  if (!id) return;
  await offlineById(id);
  await deleteById(id);
}

// ========== 收集需要清理的公告 ID ==========
const cleanupIds = [];

// ==================== 测试用例 ====================

// ── §1 公告分类与权限 ──
async function test_§1_权限校验() {
  console.log('\n📋 §1 公告分类与权限');

  // §1.1 空间站公告需要管理员权限 — 普通用户不能创建
  saveSession('admin');
  if (await loginAs(CONFIG.normalEmail)) {
    const res = await POST('/space-announcement/create', makeCreateRo());
    assert('§1.1 普通用户创建空间站公告被拒绝', res.success === false, res);
    assert('§1.1 错误码非500', res.code !== 500, res.code);
  }
  restoreSession('admin');

  // §1.2 空间站公告缺少 spaceId
  const noSpaceRes = await POST('/space-announcement/create', makeCreateRo({ spaceId: null }));
  assert('§1.2 空间站公告缺spaceId被拒绝', noSpaceRes.success === false, noSpaceRes);
  assert('§1.2 错误码非500', noSpaceRes.code !== 500, noSpaceRes.code);

  // §1.3 管理员可以创建空间站公告
  const adminRes = await POST('/space-announcement/create', makeCreateRo());
  assert('§1.3 管理员创建空间站公告成功', adminRes.success === true, adminRes);
  if (adminRes.success && adminRes.data?.id) {
    cleanupIds.push(String(adminRes.data.id));
  }
}

// ── §2 编辑公告 ──
async function test_§2_编辑公告() {
  console.log('\n📋 §2 编辑公告');

  // 创建一条立即发布公告
  const id = await createAndGetId({ title: '编辑测试-原标题' });
  assert('§2.0 创建公告成功', id != null, id);
  if (!id) return;
  cleanupIds.push(id);

  // §2.1 编辑当前生效公告
  const updateRes = await POST('/space-announcement/update', {
    id: Number(id),
    title: '编辑测试-新标题',
    content: '<p>更新后的内容</p>',
    isPopup: true,
  });
  assert('§2.1 编辑成功 (data=null, Void返回)', updateRes.success === true, updateRes);

  // §2.2 验证编辑后数据
  const detail = await GET(`/space-announcement/detail?id=${id}`);
  assert('§2.2 标题已更新', detail.data?.title === '编辑测试-新标题', detail.data?.title);
  assert('§2.2 内容已更新', detail.data?.content === '<p>更新后的内容</p>', detail.data?.content);
  assert('§2.2 isPopup已更新', detail.data?.isPopup === true, detail.data?.isPopup);
  assert('§2.2 publishTime已刷新', detail.data?.publishTime != null, detail.data?.publishTime);

  // §2.3 编辑后清空已读记录（弹窗重新生效）
  // 先查看详情写已读，再编辑，再查未读弹窗应有此公告
  // detail 已在上面调过（写了已读），现在编辑清空已读
  await POST('/space-announcement/update', {
    id: Number(id),
    title: '编辑测试-再次编辑',
    content: '<p>再次更新</p>',
    isPopup: true,
  });
  const unread = await GET(`/space-announcement/unread-popup?spaceId=${CONFIG.spaceId}`);
  const found = unread.data?.find(a => String(a.id) === id);
  assert('§2.3 编辑后弹窗重新生效（已读记录被清空）', found != null, unread.data);

  // §2.4 只能编辑 ACTIVE 公告 — 下线后编辑应失败
  await offlineById(id);
  const editOffline = await POST('/space-announcement/update', {
    id: Number(id),
    title: '尝试编辑下线公告',
    content: '<p>不应成功</p>',
    isPopup: false,
  });
  assert('§2.4 下线公告不能编辑', editOffline.success === false, editOffline);

  // §2.5 普通用户不能编辑空间站公告
  // 先创建一条新的 active
  restoreSession('admin');
  const id2 = await createAndGetId({ title: '权限编辑测试' });
  if (id2) {
    cleanupIds.push(id2);
    saveSession('admin');
    if (await loginAs(CONFIG.normalEmail)) {
      const res = await POST('/space-announcement/update', {
        id: Number(id2),
        title: '普通用户尝试编辑',
        content: '<p>不应成功</p>',
        isPopup: false,
      });
      assert('§2.5 普通用户编辑被拒绝', res.success === false, res);
      assert('§2.5 错误码非500', res.code !== 500, res.code);
    }
    restoreSession('admin');
  }
}

// ── §3 有效期设置 ──
async function test_§3_有效期() {
  console.log('\n📋 §3 有效期设置');

  // §3.1 创建带有效期的公告
  const expireTime = futureTime(60); // 1小时后
  const id = await createAndGetId({ title: '有效期测试', expireTime });
  assert('§3.1 创建带有效期公告成功', id != null, id);
  if (!id) return;
  cleanupIds.push(id);

  const detail = await GET(`/space-announcement/detail?id=${id}`);
  assert('§3.1 expireTime 已设置', detail.data?.expireTime != null, detail.data?.expireTime);

  // §3.2 不设有效期 → 永久有效
  const id2 = await createAndGetId({ title: '永久有效测试' });
  assert('§3.2 创建永久有效公告成功', id2 != null, id2);
  if (id2) {
    cleanupIds.push(id2);
    const d2 = await GET(`/space-announcement/detail?id=${id2}`);
    assert('§3.2 expireTime 为 null', d2.data?.expireTime == null, d2.data?.expireTime);
  }

  // §3.3 编辑时修改有效期
  if (id2) {
    const newExpire = futureTime(120);
    await POST('/space-announcement/update', {
      id: Number(id2),
      title: '永久有效测试',
      content: '<p>测试正文内容</p>',
      isPopup: false,
      expireTime: newExpire,
    });
    const d3 = await GET(`/space-announcement/detail?id=${id2}`);
    assert('§3.3 编辑后有效期已更新', d3.data?.expireTime != null, d3.data?.expireTime);
  }

  // §3.4 编辑时清除有效期
  if (id2) {
    await POST('/space-announcement/update', {
      id: Number(id2),
      title: '永久有效测试',
      content: '<p>测试正文内容</p>',
      isPopup: false,
      expireTime: null,
    });
    const d4 = await GET(`/space-announcement/detail?id=${id2}`);
    assert('§3.4 编辑后有效期已清除', d4.data?.expireTime == null, d4.data?.expireTime);
  }
}

// ── §4 弹窗提示 ──
async function test_§4_弹窗() {
  console.log('\n📋 §4 弹窗提示');

  // §4.1 创建弹窗公告
  const id = await createAndGetId({ title: '弹窗测试', isPopup: true });
  assert('§4.1 创建弹窗公告成功', id != null, id);
  if (!id) return;
  cleanupIds.push(id);

  // §4.2 unread-popup 接口返回此公告
  const unread = await GET(`/space-announcement/unread-popup?spaceId=${CONFIG.spaceId}`);
  assert('§4.2 unread-popup 返回成功', unread.success === true, unread);
  const found = unread.data?.find(a => String(a.id) === id);
  assert('§4.2 弹窗公告在未读列表中', found != null, unread.data);
  if (found) {
    assert('§4.2 返回 category', found.category != null, found.category);
    assert('§4.2 返回 title', typeof found.title === 'string', found.title);
    assert('§4.2 返回 content', typeof found.content === 'string', found.content);
  }

  // §4.3 查看详情后写已读，再查 unread-popup 不含此公告
  await GET(`/space-announcement/detail?id=${id}`);
  const unread2 = await GET(`/space-announcement/unread-popup?spaceId=${CONFIG.spaceId}`);
  const found2 = unread2.data?.find(a => String(a.id) === id);
  assert('§4.3 查看详情后已读，不再弹窗', found2 == null, unread2.data);

  // §4.4 isPopup=false 不弹窗
  const id2 = await createAndGetId({ title: '不弹窗测试', isPopup: false });
  if (id2) {
    cleanupIds.push(id2);
    const unread3 = await GET(`/space-announcement/unread-popup?spaceId=${CONFIG.spaceId}`);
    const found3 = unread3.data?.find(a => String(a.id) === id2);
    assert('§4.4 isPopup=false 不在弹窗列表', found3 == null, unread3.data);
  }
}

// ── §5 发布机制 ──
async function test_§5_发布机制() {
  console.log('\n📋 §5 发布机制');

  // §5.1 立即发布 status=ACTIVE
  const id = await createAndGetId({ title: '立即发布测试', publishType: 0 });
  assert('§5.1 立即发布成功', id != null, id);
  if (id) {
    cleanupIds.push(id);
    const detail = await GET(`/space-announcement/detail?id=${id}`);
    assert('§5.1 status=1(ACTIVE)', detail.data?.status === 1, detail.data?.status);
    assert('§5.1 publishType=0(IMMEDIATE)', detail.data?.publishType === 0, detail.data?.publishType);
    assert('§5.1 publishTime 已设置', detail.data?.publishTime != null, detail.data?.publishTime);
  }

  // §5.2 立即发布覆盖旧公告 — 同类型最多1条
  const id2 = await createAndGetId({ title: '覆盖旧公告测试', publishType: 0 });
  assert('§5.2 新公告创建成功', id2 != null, id2);
  if (id2) {
    cleanupIds.push(id2);
    // 旧公告应被自动下线
    if (id) {
      const oldDetail = await GET(`/space-announcement/detail?id=${id}`);
      assert('§5.2 旧公告被自动下线(status=2)', oldDetail.data?.status === 2, oldDetail.data?.status);
    }
    // 新公告是 ACTIVE
    const active = await GET(`/space-announcement/active?category=1&spaceId=${CONFIG.spaceId}`);
    assert('§5.2 当前生效是新公告', String(active.data?.id) === id2, active.data?.id);
  }

  // §5.3 定时发布 status=PENDING
  const scheduledTime = futureTime(30); // 30分钟后
  const schedRes = await POST('/space-announcement/create', makeCreateRo({
    title: '定时发布测试',
    publishType: 1,
    scheduledPublishTime: scheduledTime,
  }));
  assert('§5.3 定时发布创建成功', schedRes.success === true, schedRes);
  if (schedRes.success && schedRes.data?.id) {
    const schedId = String(schedRes.data.id);
    cleanupIds.push(schedId);
    assert('§5.3 status=0(PENDING)', schedRes.data.status === 0, schedRes.data.status);
    assert('§5.3 publishType=1(SCHEDULED)', schedRes.data.publishType === 1, schedRes.data.publishType);
    assert('§5.3 scheduledPublishTime 已设置', schedRes.data.scheduledPublishTime != null, schedRes.data.scheduledPublishTime);

    // §5.4 待发布列表包含此公告
    const pending = await GET(`/space-announcement/pending?category=1&spaceId=${CONFIG.spaceId}`);
    assert('§5.4 pending 返回成功', pending.success === true, pending);
    assert('§5.4 pending 是数组', Array.isArray(pending.data), pending.data);
    const pendingFound = pending.data?.find(a => String(a.id) === schedId);
    assert('§5.4 定时公告在 pending 列表中', pendingFound != null, pending.data);
  }
}

// ── §6 当前生效公告管理 ──
async function test_§6_生效管理() {
  console.log('\n📋 §6 当前生效公告管理');

  // 创建一条 ACTIVE
  const id = await createAndGetId({ title: '生效管理测试' });
  assert('§6.0 创建成功', id != null);
  if (!id) return;
  cleanupIds.push(id);

  // §6.1 获取当前生效
  const active = await GET(`/space-announcement/active?category=1&spaceId=${CONFIG.spaceId}`);
  assert('§6.1 active 返回成功', active.success === true, active);
  assert('§6.1 返回 SpaceAnnouncementVo', active.data != null, active.data);
  if (active.data) {
    assert('§6.1 含 id', active.data.id != null, active.data.id);
    assert('§6.1 含 title', typeof active.data.title === 'string', active.data.title);
    assert('§6.1 含 content', typeof active.data.content === 'string', active.data.content);
    assert('§6.1 含 status', typeof active.data.status === 'number', active.data.status);
    assert('§6.1 含 publishType', typeof active.data.publishType === 'number', active.data.publishType);
    assert('§6.1 含 publisherName', typeof active.data.publisherName === 'string', active.data.publisherName);
  }

  // §6.2 下线公告
  const offRes = await POST(`/space-announcement/offline?id=${id}`);
  assert('§6.2 下线成功', offRes.success === true, offRes);

  const afterOff = await GET(`/space-announcement/detail?id=${id}`);
  assert('§6.2 下线后 status=2', afterOff.data?.status === 2, afterOff.data?.status);
  assert('§6.2 offlineTime 已设置', afterOff.data?.offlineTime != null, afterOff.data?.offlineTime);

  // §6.3 下线后 active 为空
  const activeAfter = await GET(`/space-announcement/active?category=1&spaceId=${CONFIG.spaceId}`);
  assert('§6.3 下线后 active 返回 null', activeAfter.data == null, activeAfter.data);

  // §6.4 同类型最多1条生效（在 §5.2 已覆盖）
}

// ── §7 历史公告管理 ──
async function test_§7_历史管理() {
  console.log('\n📋 §7 历史公告管理');

  // 创建 → 下线 → 进入历史
  const id = await createAndGetId({ title: '历史管理测试' });
  if (!id) return;
  cleanupIds.push(id);
  await offlineById(id);

  // §7.1 历史列表包含此公告
  const history = await GET(`/space-announcement/history?category=1&spaceId=${CONFIG.spaceId}`);
  assert('§7.1 history 返回成功', history.success === true, history);
  assert('§7.1 history 是数组', Array.isArray(history.data), history.data);
  const found = history.data?.find(a => String(a.id) === id);
  assert('§7.1 下线公告在历史列表', found != null, history.data?.map(a => String(a.id)));

  // §7.2 发布人信息
  if (found) {
    assert('§7.2 publisherName 非空', found.publisherName != null && found.publisherName !== '', found.publisherName);
    assert('§7.2 publisherId 非空', found.publisherId != null, found.publisherId);
  }

  // §7.3 软删除
  const delRes = await POST(`/space-announcement/delete?id=${id}`);
  assert('§7.3 软删除成功', delRes.success === true, delRes);

  // 删除后不在历史列表
  const history2 = await GET(`/space-announcement/history?category=1&spaceId=${CONFIG.spaceId}`);
  const found2 = history2.data?.find(a => String(a.id) === id);
