package com.yottastudios.ns.collabspace.shared.interceptor;

import com.yottastudios.ns.collabspace.auth.enums.AuthException;
import com.yottastudios.ns.collabspace.control.check.PermissionChecker;
import com.yottastudios.ns.collabspace.core.exception.BusinessException;
import com.yottastudios.ns.collabspace.core.util.ExceptionUtil;
import com.yottastudios.ns.collabspace.core.util.HttpContextUtil;
import com.yottastudios.ns.collabspace.grpc.IApitableGrpcClientService;
import com.yottastudios.ns.collabspace.shared.component.ResourceDefinition;
import com.yottastudios.ns.collabspace.shared.component.scanner.ApiResourceFactory;
import com.yottastudios.ns.collabspace.shared.config.properties.ConstProperties;
import com.yottastudios.ns.collabspace.shared.constants.ParamsConstants;
import com.yottastudios.ns.collabspace.shared.context.SessionContext;
import com.yottastudios.ns.collabspace.shared.holder.SpaceHolder;
import com.yottastudios.ns.collabspace.shared.holder.UserHolder;
import com.yottastudios.ns.collabspace.shared.util.ApiHelper;
import com.yottastudios.ns.collabspace.shared.util.JwtUtil;
import com.yottastudios.ns.collabspace.space.entity.SpaceEntity;
import com.yottastudios.ns.collabspace.space.enums.SpaceException;
import com.yottastudios.ns.collabspace.space.mapper.SpaceMapper;
import jakarta.annotation.Resource;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import lombok.extern.slf4j.Slf4j;
import org.springframework.web.servlet.HandlerInterceptor;

import static com.yottastudios.ns.collabspace.auth.enums.AuthException.NONE_RESOURCE;

/**
 * <p>
 * Resource verification interceptor
 * 1.space management resource check
 * 2.Node resource check
 * </p>
 *
 * @author Shawn Deng
 */
@Slf4j
public class ResourceInterceptor extends AbstractServletSupport implements HandlerInterceptor {

    @Resource
    private ApiResourceFactory apiResourceFactory;

    @Resource
    private ConstProperties constProperties;

    @Resource
    private PermissionChecker permissionChecker;
    @Resource
    private SpaceMapper spaceMapper;
    @Resource
    private IApitableGrpcClientService apitableGrpcClientService;

    @Override
    public boolean preHandle(HttpServletRequest request, HttpServletResponse response,
                             Object handler) {
        String requestPath = resolveServletPath(request);
        ResourceDefinition resourceDef =
            apiResourceFactory.getResourceByUrl(requestPath, request.getMethod());
        if (resourceDef == null) {
            log.error("Request path [{}] is not exist", requestPath);
            throw new BusinessException(NONE_RESOURCE);
        }

        if (resourceDef.getExternalOnly() && constProperties.isMirror()) {// collabspace只有mirror环境会因只读拒绝掉一些操作
            throw new BusinessException(AuthException.EXTERNAL_ONLY);
        }

        if (!resourceDef.getRequiredLogin()) {
            return true;
        }

        String jwtToken = JwtUtil.getJwtFromRequest(request);
        Long userId = JwtUtil.getUserIdAsLong(jwtToken);
        String apiKey = null;
        if (!HttpContextUtil.hasSession() && userId == null) {
            // Get API KEY
            apiKey = ApiHelper.getApiKey(request);
            userId = apitableGrpcClientService.selectUserIdByApiKey(apiKey);

            if (userId == null) {
                throw new BusinessException(AuthException.UNAUTHORIZED);
            }
        } else if (userId == null) {
            // UserId in Session Cookies
            userId = SessionContext.getUserId();
        }
        UserHolder.set(userId);

        // 先判断下holder中的space是否存在，如果存在且状态是停用，那么直接返回资源不存在
        String spaceId = request.getHeader(ParamsConstants.SPACE_ID);
        if (spaceId != null && !spaceId.isEmpty()) {
            SpaceEntity spaceEntity = spaceMapper.selectById(spaceId);
            if (spaceEntity != null && spaceEntity.getIsForbid()){
                throw new BusinessException(AuthException.UNAUTHORIZED);
            }
        }

        if (resourceDef.getRequiredPermission()) {
            ExceptionUtil.isNotNull(spaceId, SpaceException.NOT_EXIST);
            SpaceHolder.set(spaceId);
            // todo other perm
        }

        if (resourceDef.getRequiredSpaceAdmin()) {
            ExceptionUtil.isNotNull(spaceId, SpaceException.NOT_EXIST);
            permissionChecker.requireUser(userId).onSpace(spaceId).needAdmin();
        }

        return true;
    }
}

