// ── 维度 5：注入防护与特殊字符 ──
async function test_注入防护() {
  console.log('\n🛡️ 维度5: 注入防护 + 特殊字符');

  // 5.1 title 中的特殊字符
  const specialChars = ['<script>alert(1)</script>', "' OR 1=1 --", '"; DROP TABLE xxx;', '&&||', '🎉🎊'];
  for (const ch of specialChars) {
    const res = await POST('/space-announcement/create', makeCreateRo({ title: `测试${ch}` }));
    assert(`S2 title 含 "${ch.slice(0, 20)}" 不报500`,
      res.success === true || (res.code && res.code !== 500), res);
    if (res.success && res.data?.id) {
      cleanupIds.push(String(res.data.id));
    }
  }

  // 5.2 content 中的 XSS
  const xssContent = '<img src=x onerror=alert(1)><script>document.cookie</script>';
  const xssRes = await POST('/space-announcement/create', makeCreateRo({ content: xssContent }));
  assert('S2 content XSS 不报500',
    xssRes.success === true || (xssRes.code && xssRes.code !== 500), xssRes);
  if (xssRes.success && xssRes.data?.id) {
    cleanupIds.push(String(xssRes.data.id));
  }

  // 5.3 spaceId SQL 注入
  const sqlInjSpaceId = await GET(`/space-announcement/banner?spaceId=${encodeURIComponent("' OR 1=1 --")}`);
  assert('S8 spaceId SQL注入不报500',
    sqlInjSpaceId.success === true || (sqlInjSpaceId.code && sqlInjSpaceId.code !== 500), sqlInjSpaceId);

  // 5.4 超长 title (恰好 100 字符应成功)
  const title100 = await POST('/space-announcement/create', makeCreateRo({ title: 'C'.repeat(100) }));
  assert('S2 title 恰好100字符成功', title100.success === true, title100);
  if (title100.success && title100.data?.id) {
    cleanupIds.push(String(title100.data.id));
  }
}

// ── 维度 7：多账号权限（补充） ──
async function test_多账号补充() {
  console.log('\n👤👤 维度7: 多账号权限补充');

  saveSession('admin');

  // 7.1 普通用户可以查看 banner
  if (await loginAs(CONFIG.normalEmail)) {
