  restoreSession('admin');
  const idDel = await createAndGetId({ title: '多账号删除测试' });
  if (idDel) {
    cleanupIds.push(idDel);
    await offlineById(idDel);
    saveSession('admin');
    if (await loginAs(CONFIG.normalEmail)) {
      const res = await POST(`/space-announcement/delete?id=${idDel}`);
      assert('S7 普通用户删除被拒绝', res.success === false, res);
      assert('S7 普通用户删除非500', res.code !== 500, res.code);
    }
    restoreSession('admin');
  }
}

// ── 维度 8：不存在/异常数据 ──
async function test_异常数据() {
