  const promises2 = Array.from({ length: 5 }, () =>
    GET(`/space-announcement/active?category=1&spaceId=${CONFIG.spaceId}`)
  );
  const results2 = await Promise.all(promises2);
  const allOk2 = results2.every(r => r.success === true);
  assert('S6 5个并发 active 请求都成功', allOk2);
}

