// ── 维度 12：数据重复检测 ──
async function test_重复检测() {
  console.log('\n🐛 维度12: 数据重复检测');

  // 12.1 同类型同空间站不会有2条 ACTIVE（覆盖逻辑）
  const id1 = await createAndGetId({ title: '重复检测-1' });
  const id2 = await createAndGetId({ title: '重复检测-2' });
  if (id1) cleanupIds.push(id1);
  if (id2) cleanupIds.push(id2);

  const active = await GET(`/space-announcement/active?category=1&spaceId=${CONFIG.spaceId}`);
  assert('S5.2/S6.4 同类型同空间最多1条ACTIVE', active.data == null || String(active.data.id) === id2, active.data);

  // 12.2 已读记录不会重复（唯一索引 uk_announcement_user）
  if (id2) {
    // 连续两次查看详情
    await GET(`/space-announcement/detail?id=${id2}`);
    await GET(`/space-announcement/detail?id=${id2}`);
    // 如果没报错说明唯一索引处理正确（hasRead 检查 + 唯一索引兜底）
    assert('S4.3 重复查看详情不报错', true);
  }
}

// ── 维度 13：错误码规范 ──
async function test_错误码() {
  console.log('\n🔢 维度13: 错误码规范');

  // 13.1 参数校验错误 → 非 500
  const r1 = await POST('/space-announcement/create', {});
  assert('S2 空body参数校验 success=false', r1.success === false, r1);
  assert('S2 空body参数校验 非500', r1.code !== 500, r1.code);

  // 13.2 权限不足 → 非 500（在 S1.1 已覆盖）

  // 13.3 业务异常（编辑非ACTIVE）→ 非 500
  const id = await createAndGetId({ title: '错误码测试' });
  if (id) {
    cleanupIds.push(id);
    await offlineById(id);
