    assert('S2.4 编辑非ACTIVE 非500', r2.code !== 500, r2.code);
  }

  // 13.4 删除非OFFLINE → 非 500
  const id2 = await createAndGetId({ title: '错误码测试2' });
  if (id2) {
    cleanupIds.push(id2);
    const r3 = await POST(`/space-announcement/delete?id=${id2}`);
    assert('S7.4 删除ACTIVE success=false', r3.success === false, r3);
