  }
}

// ── 未登录访问 ──
async function test_未登录() {
  console.log('\n🔒 未登录访问');
  saveSession('admin');
  cookie = '';
  xsrfToken = '';

  // GET 接口
  const r1 = await rawFetch('GET', `${CONFIG.host}/api/v1/space-announcement/banner?spaceId=${CONFIG.spaceId}`);
  assert('S8 未登录 banner 不报500', r1.status !== 500, r1.status);

  // POST 写接口
  const r2 = await rawFetch('POST', `${CONFIG.host}/api/v1/space-announcement/create`,
    makeCreateRo());
  assert('S1 未登录 create 返回非200', r2.status !== 200, r2.status);

  const r3 = await rawFetch('POST', `${CONFIG.host}/api/v1/space-announcement/offline?id=1`);
  assert('S6 未登录 offline 返回非200', r3.status !== 200, r3.status);

  restoreSession('admin');
}

// ========== 清理 ==========
async function cleanup() {
  console.log('\n🧹 清理测试数据...');
  let cleaned = 0;
  for (const id of cleanupIds) {
    try {
      await offlineById(id);
      await deleteById(id);
      cleaned++;
    } catch (e) {
      // 忽略清理错误（可能已被前面的测试删除）
    }
  }
  console.log(`   清理了 ${cleaned} 条公告`);
}

// ========== 执行 ==========
async function main() {
  console.log('🚀 2210-空间站公告功能 - 接口测试');
  console.log('');
  console.log('📋 功能点覆盖清单（来自功能点对照文档）：');
  console.log('  S1. 公告分类与权限');
  console.log('  S2. 编辑公告');
  console.log('  S3. 有效期设置');
  console.log('  S4. 弹窗提示');
  console.log('  S5. 发布机制');
  console.log('  S6. 当前生效公告管理');
  console.log('  S7. 历史公告管理');
  console.log('  S8. 横幅展示');
  console.log('  S9. 公告详情');
  console.log('  S10. 纯前端功能（后端不涉及，跳过）');
  console.log('');

  try {
    await login();
    saveSession('admin');

    // 功能点测试
    await test_S1_权限校验();
    await test_S2_编辑公告();
    await test_S3_有效期();
    await test_S4_弹窗();
    await test_S5_发布机制();
    await test_S6_生效管理();
    await test_S7_历史管理();
    await test_S8_横幅();
    await test_S9_详情();

    // 维度补充测试
    await test_参数校验();
    await test_注入防护();
    await test_多账号补充();
    await test_异常数据();
    await test_并发();
    await test_响应结构();
    await test_重复检测();
    await test_错误码();
    await test_未登录();

    // 清理
    restoreSession('admin');
    await cleanup();
  } catch (e) {
    if (e.cause?.code === 'ECONNREFUSED') {
      console.log('\n❌ 无法连接测试环境，请检查网络');
    } else {
      console.log(`\n❌ 异常: ${e.stack || e.message}`);
    }
    // 尝试清理
    try {
      restoreSession('admin');
      await cleanup();
    } catch (_) {}
    process.exit(1);
  }

  console.log(`\n=============================`);
  console.log(`✅ 通过: ${passed}  ❌ 失败: ${failed}  📊 总计: ${passed + failed}`);
  console.log(`=============================`);
  process.exit(failed > 0 ? 1 : 0);
}

main();

