// ── 维度 13：错误码规范 ──
async function test_错误码() {
  console.log('\n🔢 维度13: 错误码规范');

  // 13.1 参数校验错误 → 非 500
  const r1 = await POST('/space-announcement/create', {});
  assert('S2 空body参数校验 success=false', r1.success === false, r1);
  assert('S2 空body参数校验 非500', r1.code !== 500, r1.code);

  // 13.2 权限不足 → 非 500（在 S1.1 已覆盖）

