/**
 * 2210-空间站公告功能 - 接口测试脚本
 *
 * 用法: node test-api.js
 * 要求: Node.js 18+（原生 fetch）
 * 自动登录测试环境，无需手动填 Cookie
 *
 * 接口清单（10 个）：
 *   POST /space-announcement/create    — 创建/发布公告
 *   POST /space-announcement/update    — 编辑当前生效公告
 *   POST /space-announcement/offline   — 下线公告
 *   POST /space-announcement/delete    — 删除历史公告（软删除）
 *   GET  /space-announcement/active    — 获取当前生效公告
 *   GET  /space-announcement/pending   — 获取待发布公告列表
 *   GET  /space-announcement/history   — 获取历史公告列表
 *   GET  /space-announcement/banner    — 获取横幅公告（用户端）
 *   GET  /space-announcement/detail    — 获取公告详情（同时记录已读）
 *   GET  /space-announcement/unread-popup — 获取未读弹窗公告
 */

// ========== 配置 ==========
const CONFIG = {
  host: 'http://xcollabspace-test.xtool-staging.yottastudios.com',
  adminEmail: 'admin@apitable.com',            // 空间站管理员（apitable admin, is_admin=1 on spcQB8z3iXMF0）
  normalEmail: 'nanbei2@yottastudios.com',     // 普通成员（非管理员，同空间站）
  spaceId: 'spcQB8z3iXMF0',                   // nanbei 测试空间站
};

// ========== 测试框架 ==========
let passed = 0;
let failed = 0;
let cookie = '';
let xsrfToken = '';

function assert(name, condition, detail) {
  if (condition) {
    console.log(`  ✅ ${name}`);
    passed++;
  } else {
    console.log(`  ❌ ${name}`);
    if (detail !== undefined)
      console.log(`     实际值:`, typeof detail === 'object'
        ? JSON.stringify(detail).slice(0, 300) : detail);
    failed++;
  }
}

// ========== HTTP 工具 ==========
function parseCookies(res) {
  const cookies = {};
  const setCookieHeaders = res.headers.getSetCookie?.() || [];
  for (const header of setCookieHeaders) {
    const [kv] = header.split(';');
    const eq = kv.indexOf('=');
    if (eq > 0) {
      cookies[kv.substring(0, eq).trim()] = kv.substring(eq + 1).trim();
    }
  }
  return cookies;
}

async function rawFetch(method, url, body) {
  const headers = {
    'x-space-id': CONFIG.spaceId,
    'content-type': 'application/json',
  };
  if (cookie) headers['cookie'] = cookie;
  if (xsrfToken) headers['x-xsrf-token'] = xsrfToken;

  const opts = { method, headers, redirect: 'manual' };
  if (body) opts.body = JSON.stringify(body);
  return fetch(url, opts);
}

async function GET(path) {
  const res = await rawFetch('GET', `${CONFIG.host}/api/v1${path}`);
  return res.json();
}

async function POST(path, body) {
  const res = await rawFetch('POST', `${CONFIG.host}/api/v1${path}`, body);
  return res.json();
}

// ========== 登录管理 ==========
async function loginWithEmail(email) {
  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${encodeURIComponent(email)}`,
    { redirect: 'manual' });
  const cookies = parseCookies(res);
  if (!cookies.SESSION) return false;
  xsrfToken = cookies['XSRF-TOKEN'] || '';
  const tjwt = cookies['TJWT'] || '';
  cookie = `SESSION=${cookies.SESSION}; XSRF-TOKEN=${xsrfToken}` + (tjwt ? `; TJWT=${tjwt}` : '');
  return true;
}

async function login() {
  console.log(`🔑 登录 ${CONFIG.adminEmail} ...`);
  if (!await loginWithEmail(CONFIG.adminEmail)) {
    console.log('❌ 登录失败');
    process.exit(1);
  }
  console.log(`   ✅ 登录成功\n`);
}

let savedSessions = {};
function saveSession(name) {
  savedSessions[name] = { cookie, xsrfToken };
}
function restoreSession(name) {
  ({ cookie, xsrfToken } = savedSessions[name]);
}

async function loginAs(email) {
  if (!await loginWithEmail(email)) {
    console.log(`  ⚠️  登录 ${email} 失败，跳过`);
    return false;
  }
  return true;
}

// ========== 辅助函数 ==========
function futureTime(minutesFromNow) {
  const d = new Date(Date.now() + minutesFromNow * 60 * 1000);
  const pad = n => String(n).padStart(2, '0');
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}`;
}

function makeCreateRo(overrides = {}) {
  return {
    category: 1,
    spaceId: CONFIG.spaceId,
    title: `测试公告-${Date.now()}`,
    content: '<p>测试正文内容</p>',
    isPopup: false,
    publishType: 0,
    ...overrides,
  };
}

async function createAndGetId(overrides = {}) {
  const res = await POST('/space-announcement/create', makeCreateRo(overrides));
  return res.success ? String(res.data?.id) : null;
}

async function offlineById(id) {
  await POST(`/space-announcement/offline?id=${id}`);
}

async function deleteById(id) {
  await POST(`/space-announcement/delete?id=${id}`);
}

const cleanupIds = [];

// ==================== 测试用例 ====================

// ── S1 公告分类与权限 ──
async function test_S1_权限校验() {
  console.log('\n📋 S1 公告分类与权限');

  // S1.1 管理员创建空间站公告成功
  const adminRes = await POST('/space-announcement/create', makeCreateRo({ title: '管理员创建测试' }));
  assert('S1.1 管理员创建空间站公告成功', adminRes.success === true, adminRes);
  assert('S1.1 返回 data 不为 null', adminRes.data != null, adminRes.data);
  assert('S1.1 返回 id', adminRes.data?.id != null, adminRes.data?.id);
  assert('S1.1 返回 category=1', adminRes.data?.category === 1, adminRes.data?.category);
  assert('S1.1 返回 status=1(ACTIVE)', adminRes.data?.status === 1, adminRes.data?.status);
  assert('S1.1 返回 spaceId 匹配', adminRes.data?.spaceId === CONFIG.spaceId, adminRes.data?.spaceId);
  assert('S1.1 publisherName 非空', adminRes.data?.publisherName != null && adminRes.data?.publisherName !== '', adminRes.data?.publisherName);
  if (adminRes.data?.id) cleanupIds.push(String(adminRes.data.id));

  // S1.2 普通用户不能创建空间站公告
  saveSession('admin');
  if (await loginAs(CONFIG.normalEmail)) {
    const res = await POST('/space-announcement/create', makeCreateRo({ title: '普通用户尝试创建' }));
    assert('S1.2 普通用户创建空间站公告被拒绝', res.success === false, res);
    assert('S1.2 错误码非500', res.code !== 500, res.code);
    assert('S1.2 返回权限相关错误', res.code === 702 || res.code === 603 || res.message?.includes('权限'), res);

    // S1.3 普通用户不能下线
    const offRes = await POST(`/space-announcement/offline?id=${adminRes.data?.id || 1}`);
    assert('S1.3 普通用户下线被拒绝', offRes.success === false, offRes);
    assert('S1.3 错误码非500', offRes.code !== 500, offRes.code);

    // S1.4 普通用户不能编辑
    if (adminRes.data?.id) {
      const updRes = await POST('/space-announcement/update', {
        id: adminRes.data.id, title: '普通用户编辑', content: '<p>x</p>', isPopup: false,
      });
      assert('S1.4 普通用户编辑被拒绝', updRes.success === false, updRes);
      assert('S1.4 错误码非500', updRes.code !== 500, updRes.code);
    }

    // S1.5 普通用户可以查看 banner
    const bannerRes = await GET(`/space-announcement/banner?spaceId=${CONFIG.spaceId}`);
    assert('S1.5 普通用户可查看 banner', bannerRes.success === true, bannerRes);

    // S1.6 普通用户可以查看 detail
    if (adminRes.data?.id) {
      const detailRes = await GET(`/space-announcement/detail?id=${adminRes.data.id}`);
      assert('S1.6 普通用户可查看 detail', detailRes.success === true, detailRes);
    }

    // S1.7 普通用户可以查看 unread-popup
    const unreadRes = await GET(`/space-announcement/unread-popup?spaceId=${CONFIG.spaceId}`);
    assert('S1.7 普通用户可查看 unread-popup', unreadRes.success === true, unreadRes);

    // S1.8 普通用户可以查看 active
    const activeRes = await GET(`/space-announcement/active?category=1&spaceId=${CONFIG.spaceId}`);
    assert('S1.8 普通用户可查看 active', activeRes.success === true, activeRes);

    // S1.9 普通用户可以查看 pending
    const pendingRes = await GET(`/space-announcement/pending?category=1&spaceId=${CONFIG.spaceId}`);
    assert('S1.9 普通用户可查看 pending', pendingRes.success === true, pendingRes);

    // S1.10 普通用户可以查看 history
    const historyRes = await GET(`/space-announcement/history?category=1&spaceId=${CONFIG.spaceId}`);
    assert('S1.10 普通用户可查看 history', historyRes.success === true, historyRes);
  }
  restoreSession('admin');

  // S1.11 空间站公告缺少 spaceId
  const noSpaceRes = await POST('/space-announcement/create', makeCreateRo({ spaceId: null }));
  assert('S1.11 空间站公告缺spaceId被拒绝', noSpaceRes.success === false, noSpaceRes);
  assert('S1.11 错误码非500', noSpaceRes.code !== 500, noSpaceRes.code);

  // S1.12 空间站公告 spaceId 为空字符串
  const emptySpaceRes = await POST('/space-announcement/create', makeCreateRo({ spaceId: '' }));
  assert('S1.12 spaceId空字符串被拒绝', emptySpaceRes.success === false, emptySpaceRes);
  assert('S1.12 错误码非500', emptySpaceRes.code !== 500, emptySpaceRes.code);
}

// ── S2 编辑公告 ──
async function test_S2_编辑公告() {
  console.log('\n📋 S2 编辑公告');

  const id = await createAndGetId({ title: '编辑测试-原标题', content: '<p>原始内容</p>', isPopup: false });
  assert('S2.0 创建公告成功', id != null, id);
  if (!id) return;
  cleanupIds.push(id);

  // S2.1 编辑标题
  const updateRes = await POST('/space-announcement/update', {
    id: Number(id), title: '编辑测试-新标题', content: '<p>更新后的内容</p>', isPopup: true,
  });
  assert('S2.1 编辑成功 (Void返回)', updateRes.success === true, updateRes);
  assert('S2.1 data=null (ResponseData<Void>)', updateRes.data == null, updateRes.data);

  // S2.2 验证编辑后数据 — 逐字段校验
  const detail = await GET(`/space-announcement/detail?id=${id}`);
  assert('S2.2 detail 成功', detail.success === true, detail);
  assert('S2.2 标题已更新', detail.data?.title === '编辑测试-新标题', detail.data?.title);
  assert('S2.2 内容已更新', detail.data?.content === '<p>更新后的内容</p>', detail.data?.content);
  assert('S2.2 isPopup 已更新为 true', detail.data?.isPopup === true, detail.data?.isPopup);
  assert('S2.2 publishTime 已刷新(非null)', detail.data?.publishTime != null, detail.data?.publishTime);
  assert('S2.2 status 仍为 ACTIVE', detail.data?.status === 1, detail.data?.status);
  assert('S2.2 category 未变', detail.data?.category === 1, detail.data?.category);
  assert('S2.2 spaceId 未变', detail.data?.spaceId === CONFIG.spaceId, detail.data?.spaceId);

  // S2.3 编辑后清空已读记录（弹窗重新生效）
  // detail 已在上面调过（写了已读），现在编辑清空已读
  await POST('/space-announcement/update', {
    id: Number(id), title: '编辑测试-再次编辑', content: '<p>再次更新</p>', isPopup: true,
  });
  const unread = await GET(`/space-announcement/unread-popup?spaceId=${CONFIG.spaceId}`);
  const found = unread.data?.find(a => String(a.id) === id);
  assert('S2.3 编辑后弹窗重新生效（已读记录被清空）', found != null, unread.data);

  // S2.4 编辑有效期：设置 → 验证 → 清除 → 验证
  const newExpire = futureTime(120);
  await POST('/space-announcement/update', {
    id: Number(id), title: '有效期编辑', content: '<p>x</p>', isPopup: false, expireTime: newExpire,
  });
  const d1 = await GET(`/space-announcement/detail?id=${id}`);
  assert('S2.4 编辑后有效期已设置', d1.data?.expireTime != null, d1.data?.expireTime);

  await POST('/space-announcement/update', {
    id: Number(id), title: '有效期清除', content: '<p>x</p>', isPopup: false, expireTime: null,
  });
  const d2 = await GET(`/space-announcement/detail?id=${id}`);
  assert('S2.4 编辑后有效期已清除', d2.data?.expireTime == null, d2.data?.expireTime);

  // S2.5 只能编辑 ACTIVE — 下线后编辑失败
  await offlineById(id);
  const editOffline = await POST('/space-announcement/update', {
    id: Number(id), title: '尝试编辑下线公告', content: '<p>不应成功</p>', isPopup: false,
  });
  assert('S2.5 下线公告不能编辑', editOffline.success === false, editOffline);
  assert('S2.5 错误码非500', editOffline.code !== 500, editOffline.code);

  // S2.6 编辑不存在的公告
  const editNotExist = await POST('/space-announcement/update', {
    id: 1, title: '不存在', content: '<p>x</p>', isPopup: false,
  });
  assert('S2.6 编辑不存在公告 success=false', editNotExist.success === false, editNotExist);
  assert('S2.6 错误码非500', editNotExist.code !== 500, editNotExist.code);

  // S2.7 title 恰好 100 字符
  const id2 = await createAndGetId({ title: '100字符边界测试' });
  if (id2) {
    cleanupIds.push(id2);
    const r100 = await POST('/space-announcement/update', {
      id: Number(id2), title: 'X'.repeat(100), content: '<p>边界</p>', isPopup: false,
    });
    assert('S2.7 title 恰好100字符成功', r100.success === true, r100);

    // S2.8 title 101 字符
    const r101 = await POST('/space-announcement/update', {
      id: Number(id2), title: 'X'.repeat(101), content: '<p>超限</p>', isPopup: false,
    });
    assert('S2.8 title 101字符被拒绝', r101.success === false, r101);
  }
}

// ── S3 有效期设置 ──
async function test_S3_有效期() {
  console.log('\n📋 S3 有效期设置');

  // S3.1 创建带有效期的公告
  const expireTime = futureTime(60);
  const id = await createAndGetId({ title: '有效期测试', expireTime });
  assert('S3.1 创建带有效期公告成功', id != null, id);
  if (!id) return;
  cleanupIds.push(id);

  const detail = await GET(`/space-announcement/detail?id=${id}`);
  assert('S3.1 expireTime 已设置', detail.data?.expireTime != null, detail.data?.expireTime);
  assert('S3.1 expireTime 格式正确(yyyy-MM-dd HH:mm)', /^\d{4}-\d{2}-\d{2} \d{2}:\d{2}$/.test(detail.data?.expireTime), detail.data?.expireTime);

  // S3.2 不设有效期 → 永久有效
  const id2 = await createAndGetId({ title: '永久有效测试' });
  assert('S3.2 创建永久有效公告成功', id2 != null, id2);
  if (id2) {
    cleanupIds.push(id2);
    const d2 = await GET(`/space-announcement/detail?id=${id2}`);
    assert('S3.2 expireTime 为 null', d2.data?.expireTime == null, d2.data?.expireTime);
    assert('S3.2 status=ACTIVE', d2.data?.status === 1, d2.data?.status);
  }

  // S3.3 空字符串 expireTime 也算永久
  const id3 = await createAndGetId({ title: '空字符串有效期', expireTime: '' });
  assert('S3.3 空字符串expireTime创建成功', id3 != null, id3);
  if (id3) {
    cleanupIds.push(id3);
    const d3 = await GET(`/space-announcement/detail?id=${id3}`);
    assert('S3.3 expireTime 为 null', d3.data?.expireTime == null, d3.data?.expireTime);
  }
}

// ── S4 弹窗提示 ──
async function test_S4_弹窗() {
  console.log('\n📋 S4 弹窗提示');

  // S4.1 创建弹窗公告 + 字段校验
  const id = await createAndGetId({ title: '弹窗测试', isPopup: true });
  assert('S4.1 创建弹窗公告成功', id != null, id);
  if (!id) return;
  cleanupIds.push(id);

  // S4.2 unread-popup 接口包含此公告
  const unread = await GET(`/space-announcement/unread-popup?spaceId=${CONFIG.spaceId}`);
  assert('S4.2 unread-popup 返回成功', unread.success === true, unread);
  assert('S4.2 data 是数组', Array.isArray(unread.data), unread.data);
  const found = unread.data?.find(a => String(a.id) === id);
  assert('S4.2 弹窗公告在未读列表中', found != null, unread.data?.map(a => String(a.id)));
  if (found) {
    assert('S4.2 含 id', found.id != null, found.id);
    assert('S4.2 含 category(number)', typeof found.category === 'number', found.category);
    assert('S4.2 含 title(string)', typeof found.title === 'string', found.title);
    assert('S4.2 含 content(string)', typeof found.content === 'string', found.content);
    assert('S4.2 不含 status（精简VO）', found.status === undefined, found.status);
    assert('S4.2 不含 publisherName（精简VO）', found.publisherName === undefined, found.publisherName);
  }

  // S4.3 查看详情后写已读，再查不含
  await GET(`/space-announcement/detail?id=${id}`);
  const unread2 = await GET(`/space-announcement/unread-popup?spaceId=${CONFIG.spaceId}`);
  const found2 = unread2.data?.find(a => String(a.id) === id);
  assert('S4.3 查看详情后已读，不再弹窗', found2 == null, unread2.data?.map(a => String(a.id)));

  // S4.4 重复查看详情不报错（唯一索引兜底）
  const detail2 = await GET(`/space-announcement/detail?id=${id}`);
  assert('S4.4 重复查看详情不报错', detail2.success === true || detail2.code !== 500, detail2);
  const detail3 = await GET(`/space-announcement/detail?id=${id}`);
  assert('S4.4 第三次查看详情不报错', detail3.success === true || detail3.code !== 500, detail3);

  // S4.5 isPopup=false 不弹窗
  const id2 = await createAndGetId({ title: '不弹窗测试', isPopup: false });
  if (id2) {
    cleanupIds.push(id2);
    const unread3 = await GET(`/space-announcement/unread-popup?spaceId=${CONFIG.spaceId}`);
    const found3 = unread3.data?.find(a => String(a.id) === id2);
    assert('S4.5 isPopup=false 不在弹窗列表', found3 == null, unread3.data?.map(a => String(a.id)));
  }

  // S4.6 不同用户独立已读 — 普通用户看弹窗公告还是未读
  const id3 = await createAndGetId({ title: '多用户弹窗测试', isPopup: true });
  if (id3) {
