  const scheduledTime = futureTime(30);
  const schedRes = await POST('/space-announcement/create', makeCreateRo({
    title: '定时发布测试', publishType: 1, scheduledPublishTime: scheduledTime,
  }));
  assert('S5.3 定时发布创建成功', schedRes.success === true, schedRes);
  if (schedRes.success && schedRes.data?.id) {
    const schedId = String(schedRes.data.id);
