/**
 * 2210-空间站公告功能 - 接口测试脚本
 *
 * 用法: node test-api.js
 * 要求: Node.js 18+（原生 fetch）
 * 自动登录测试环境，无需手动填 Cookie
 *
 * 接口清单（10 个）：
 *   POST /space-announcement/create    — 创建/发布公告
 *   POST /space-announcement/update    — 编辑当前生效公告
 *   POST /space-announcement/offline   — 下线公告
 *   POST /space-announcement/delete    — 删除历史公告（软删除）
 *   GET  /space-announcement/active    — 获取当前生效公告
 *   GET  /space-announcement/pending   — 获取待发布公告列表
 *   GET  /space-announcement/history   — 获取历史公告列表
 *   GET  /space-announcement/banner    — 获取横幅公告（用户端）
 *   GET  /space-announcement/detail    — 获取公告详情（同时记录已读）
 *   GET  /space-announcement/unread-popup — 获取未读弹窗公告
 */

// ========== 配置 ==========
const CONFIG = {
  host: 'http://xcollabspace-test.xtool-staging.yottastudios.com',
  adminEmail: 'admin@apitable.com',            // 空间站管理员（apitable admin, is_admin=1）
  normalEmail: 'nanbei2@yottastudios.com',     // 普通成员（非管理员，同空间站）
  spaceId: 'spcQB8z3iXMF0',                   // nanbei 测试空间站
};

// ========== 测试框架 ==========
let passed = 0;
let failed = 0;
let cookie = '';
let xsrfToken = '';

function assert(name, condition, detail) {
  if (condition) {
    console.log(`  ✅ ${name}`);
    passed++;
  } else {
    console.log(`  ❌ ${name}`);
    if (detail !== undefined)
      console.log(`     实际值:`, typeof detail === 'object'
        ? JSON.stringify(detail).slice(0, 300) : detail);
    failed++;
  }
}

// ========== HTTP 工具 ==========
function parseCookies(res) {
  const cookies = {};
  const setCookieHeaders = res.headers.getSetCookie?.() || [];
  for (const header of setCookieHeaders) {
    const [kv] = header.split(';');
    const [k, v] = kv.split('=');
    cookies[k.trim()] = v.trim();
  }
  return cookies;
}

async function rawFetch(method, url, body) {
  const headers = {
    'x-space-id': CONFIG.spaceId,
    'content-type': 'application/json',
  };
  if (cookie) headers['cookie'] = cookie;
  if (xsrfToken) headers['x-xsrf-token'] = xsrfToken;

  const opts = { method, headers, redirect: 'manual' };
  if (body) opts.body = JSON.stringify(body);
  return fetch(url, opts);
}

async function GET(path) {
  const res = await rawFetch('GET', `${CONFIG.host}/api/v1${path}`);
  return res.json();
}

async function POST(path, body) {
  const res = await rawFetch('POST', `${CONFIG.host}/api/v1${path}`, body);
  return res.json();
}

// ========== 登录管理 ==========
async function login() {
  console.log(`🔑 登录 ${CONFIG.adminEmail} ...`);
  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${CONFIG.adminEmail}`,
    { redirect: 'manual' });
  const cookies = parseCookies(res);
  if (!cookies.SESSION) {
    console.log('❌ 登录失败');
    process.exit(1);
  }
  xsrfToken = cookies['XSRF-TOKEN'] || '';
  cookie = `SESSION=${cookies.SESSION}; XSRF-TOKEN=${xsrfToken}`;
  console.log(`   ✅ 登录成功\n`);
}

let savedSessions = {};
function saveSession(name) {
  savedSessions[name] = { cookie, xsrfToken };
}
function restoreSession(name) {
  ({ cookie, xsrfToken } = savedSessions[name]);
}

async function loginAs(email) {
  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${encodeURIComponent(email)}`,
    { redirect: 'manual' });
  const cookies = parseCookies(res);
  if (!cookies.SESSION) {
    console.log(`  ⚠️  登录 ${email} 失败，跳过`);
    return false;
  }
  xsrfToken = cookies['XSRF-TOKEN'] || '';
  cookie = `SESSION=${cookies.SESSION}; XSRF-TOKEN=${xsrfToken}`;
  return true;
}

// ========== 辅助函数 ==========
function futureTime(minutesFromNow) {
  const d = new Date(Date.now() + minutesFromNow * 60 * 1000);
  const pad = n => String(n).padStart(2, '0');
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}`;
}

function makeCreateRo(overrides = {}) {
  return {
    category: 1,
    spaceId: CONFIG.spaceId,
    title: `测试公告-${Date.now()}`,
    content: '<p>测试正文内容</p>',
    isPopup: false,
    publishType: 0,
    ...overrides,
  };
}

/** 创建一条公告并返回 id，失败返回 null */
async function createAndGetId(overrides = {}) {
  const res = await POST('/space-announcement/create', makeCreateRo(overrides));
  return res.success ? String(res.data?.id) : null;
}

/** 下线公告 */
async function offlineById(id) {
  await POST(`/space-announcement/offline?id=${id}`);
}

/** 软删除公告 */
async function deleteById(id) {
  await POST(`/space-announcement/delete?id=${id}`);
}

/** 完整清理：下线 → 删除 */
async function cleanupAnnouncement(id) {
  if (!id) return;
  await offlineById(id);
  await deleteById(id);
}

// ========== 收集需要清理的公告 ID ==========
const cleanupIds = [];

// ==================== 测试用例 ====================

// ── S1 公告分类与权限 ──
async function test_S1_权限校验() {
  console.log('\n📋 S1 公告分类与权限');

  // S1.1 空间站公告需要管理员权限 — 普通用户不能创建
  saveSession('admin');
  if (await loginAs(CONFIG.normalEmail)) {
    const res = await POST('/space-announcement/create', makeCreateRo());
    assert('S1.1 普通用户创建空间站公告被拒绝', res.success === false, res);
    assert('S1.1 错误码非500', res.code !== 500, res.code);
  }
  restoreSession('admin');

  // S1.2 空间站公告缺少 spaceId
  const noSpaceRes = await POST('/space-announcement/create', makeCreateRo({ spaceId: null }));
  assert('S1.2 空间站公告缺spaceId被拒绝', noSpaceRes.success === false, noSpaceRes);
  assert('S1.2 错误码非500', noSpaceRes.code !== 500, noSpaceRes.code);

  // S1.3 管理员可以创建空间站公告
  const adminRes = await POST('/space-announcement/create', makeCreateRo());
  assert('S1.3 管理员创建空间站公告成功', adminRes.success === true, adminRes);
  if (adminRes.success && adminRes.data?.id) {
    cleanupIds.push(String(adminRes.data.id));
  }
}

// ── S2 编辑公告 ──
async function test_S2_编辑公告() {
  console.log('\n📋 S2 编辑公告');

  // 创建一条立即发布公告
  const id = await createAndGetId({ title: '编辑测试-原标题' });
  assert('S2.0 创建公告成功', id != null, id);
  if (!id) return;
  cleanupIds.push(id);

  // S2.1 编辑当前生效公告
  const updateRes = await POST('/space-announcement/update', {
    id: Number(id),
    title: '编辑测试-新标题',
    content: '<p>更新后的内容</p>',
    isPopup: true,
  });
  assert('S2.1 编辑成功 (data=null, Void返回)', updateRes.success === true, updateRes);

  // S2.2 验证编辑后数据
  const detail = await GET(`/space-announcement/detail?id=${id}`);
  assert('S2.2 标题已更新', detail.data?.title === '编辑测试-新标题', detail.data?.title);
  assert('S2.2 内容已更新', detail.data?.content === '<p>更新后的内容</p>', detail.data?.content);
  assert('S2.2 isPopup已更新', detail.data?.isPopup === true, detail.data?.isPopup);
  assert('S2.2 publishTime已刷新', detail.data?.publishTime != null, detail.data?.publishTime);

  // S2.3 编辑后清空已读记录（弹窗重新生效）
  // 先查看详情写已读，再编辑，再查未读弹窗应有此公告
  // detail 已在上面调过（写了已读），现在编辑清空已读
  await POST('/space-announcement/update', {
    id: Number(id),
