    assert('S5.3 publishType=1(SCHEDULED)', schedRes.data.publishType === 1, schedRes.data.publishType);
    assert('S5.3 scheduledPublishTime 已设置', schedRes.data.scheduledPublishTime != null, schedRes.data.scheduledPublishTime);

    // S5.4 待发布列表包含此公告
