// ── 维度 12：数据重复检测 ──
async function test_重复检测() {
  console.log('\n🐛 维度12: 数据重复检测');

  // 连续创建3条 → 只有最后一条 ACTIVE
  const id1 = await createAndGetId({ title: '重复检测-1' });
  const id2 = await createAndGetId({ title: '重复检测-2' });
  const id3 = await createAndGetId({ title: '重复检测-3' });
  if (id1) cleanupIds.push(id1);
  if (id2) cleanupIds.push(id2);
  if (id3) cleanupIds.push(id3);

  const active = await GET(`/space-announcement/active?category=1&spaceId=${CONFIG.spaceId}`);
  assert('连续3条只有最后1条ACTIVE', active.data != null && String(active.data.id) === id3, active.data?.id);

  if (id1) {
    const d1 = await GET(`/space-announcement/detail?id=${id1}`);
    assert('第1条被下线(status=2)', d1.data?.status === 2, d1.data?.status);
  }
  if (id2) {
    const d2 = await GET(`/space-announcement/detail?id=${id2}`);
    assert('第2条被下线(status=2)', d2.data?.status === 2, d2.data?.status);
  }

  // 重复查看详情（已读记录幂等）
  if (id3) {
    for (let i = 0; i < 5; i++) {
      const res = await GET(`/space-announcement/detail?id=${id3}`);
      if (i === 4) assert('5次重复查看详情不报错', res.success === true || res.code !== 500, res);
    }
  }
}

// ── 维度 13：错误码规范 ──
async function test_错误码() {
  console.log('\n🔢 维度13: 错误码规范');

  // 参数校验 → 非500
  const r1 = await POST('/space-announcement/create', {});
  assert('空body success=false', r1.success === false);
  assert('空body 非500', r1.code !== 500, r1.code);

  // 编辑非ACTIVE → 非500
  const id = await createAndGetId({ title: '错误码测试' });
  if (id) {
    cleanupIds.push(id);
    await offlineById(id);
    const r2 = await POST('/space-announcement/update', {
      id: Number(id), title: '编辑下线的', content: '<p>x</p>', isPopup: false,
    });
    assert('编辑OFFLINE success=false', r2.success === false);
    assert('编辑OFFLINE 非500', r2.code !== 500, r2.code);
  }

  // 删除ACTIVE → 非500
  const id2 = await createAndGetId({ title: '错误码测试2' });
  if (id2) {
    cleanupIds.push(id2);
    const r3 = await POST(`/space-announcement/delete?id=${id2}`);
    assert('删除ACTIVE success=false', r3.success === false);
    assert('删除ACTIVE 非500', r3.code !== 500, r3.code);
  }

  // 权限不足 → 非500
  saveSession('admin');
  if (await loginAs(CONFIG.normalEmail)) {
    const r4 = await POST('/space-announcement/create', makeCreateRo());
    assert('权限不足 success=false', r4.success === false);
    assert('权限不足 非500', r4.code !== 500, r4.code);
  }
  restoreSession('admin');
}

// ── 未登录访问 ──
async function test_未登录() {
  console.log('\n🔒 未登录访问');
  saveSession('admin');
  cookie = '';
  xsrfToken = '';

  // GET 接口
  const r1 = await rawFetch('GET', `${CONFIG.host}/api/v1/space-announcement/banner?spaceId=${CONFIG.spaceId}`);
  assert('未登录 banner 不报500', r1.status !== 500, r1.status);

  const r2 = await rawFetch('GET', `${CONFIG.host}/api/v1/space-announcement/detail?id=1`);
  assert('未登录 detail 不报500', r2.status !== 500, r2.status);

  const r3 = await rawFetch('GET', `${CONFIG.host}/api/v1/space-announcement/unread-popup?spaceId=${CONFIG.spaceId}`);
  assert('未登录 unread-popup 不报500', r3.status !== 500, r3.status);

  // POST 写接口应被拒绝
  const r4 = await rawFetch('POST', `${CONFIG.host}/api/v1/space-announcement/create`, makeCreateRo());
  assert('未登录 create 非200', r4.status !== 200, r4.status);

  const r5 = await rawFetch('POST', `${CONFIG.host}/api/v1/space-announcement/offline?id=1`);
  assert('未登录 offline 非200', r5.status !== 200, r5.status);

  const r6 = await rawFetch('POST', `${CONFIG.host}/api/v1/space-announcement/update`, { id: 1, title: 'x', content: '<p>x</p>', isPopup: false });
  assert('未登录 update 非200', r6.status !== 200, r6.status);

  const r7 = await rawFetch('POST', `${CONFIG.host}/api/v1/space-announcement/delete?id=1`);
  assert('未登录 delete 非200', r7.status !== 200, r7.status);

  restoreSession('admin');
}

// ── 完整生命周期测试 ──
async function test_生命周期() {
  console.log('\n🔄 完整生命周期：创建→编辑→下线→删除');

  // 1. 创建
  const createRes = await POST('/space-announcement/create', makeCreateRo({
    title: '生命周期测试', content: '<p>初始内容</p>', isPopup: true, expireTime: futureTime(60),
  }));
  assert('lifecycle 创建成功', createRes.success === true, createRes);
  const id = createRes.success ? String(createRes.data?.id) : null;
  if (!id) return;

  // 2. 验证在各列表中
  const active = await GET(`/space-announcement/active?category=1&spaceId=${CONFIG.spaceId}`);
  assert('lifecycle ACTIVE 状态 active 有数据', active.data != null && String(active.data.id) === id);
  const banner = await GET(`/space-announcement/banner?spaceId=${CONFIG.spaceId}`);
  assert('lifecycle ACTIVE 在 banner', banner.data?.some(a => String(a.id) === id));
  const unread = await GET(`/space-announcement/unread-popup?spaceId=${CONFIG.spaceId}`);
  assert('lifecycle ACTIVE+popup 在 unread', unread.data?.some(a => String(a.id) === id));

  // 3. 编辑
  await POST('/space-announcement/update', {
    id: Number(id), title: '生命周期-已编辑', content: '<p>编辑后</p>', isPopup: false,
  });
  const detail = await GET(`/space-announcement/detail?id=${id}`);
  assert('lifecycle 编辑后标题正确', detail.data?.title === '生命周期-已编辑');
  assert('lifecycle 编辑后 isPopup=false', detail.data?.isPopup === false);

  // 4. 下线
  await offlineById(id);
  const afterOff = await GET(`/space-announcement/detail?id=${id}`);
  assert('lifecycle 下线后 status=2', afterOff.data?.status === 2);
  const activeAfter = await GET(`/space-announcement/active?category=1&spaceId=${CONFIG.spaceId}`);
  assert('lifecycle 下线后 active=null', activeAfter.data == null);
  const historyList = await GET(`/space-announcement/history?category=1&spaceId=${CONFIG.spaceId}`);
  assert('lifecycle 下线后在 history', historyList.data?.some(a => String(a.id) === id));

  // 5. 删除
  await deleteById(id);
  const historyAfter = await GET(`/space-announcement/history?category=1&spaceId=${CONFIG.spaceId}`);
  assert('lifecycle 删除后不在 history', !historyAfter.data?.some(a => String(a.id) === id));
}

// ========== 清理 ==========
async function cleanup() {
  console.log('\n🧹 清理测试数据...');
  let cleaned = 0;
  for (const id of cleanupIds) {
    try {
      await offlineById(id);
      await deleteById(id);
      cleaned++;
    } catch (e) { /* ignore */ }
  }
  console.log(`   清理了 ${cleaned} 条公告`);
}

// ========== 执行 ==========
async function main() {
  console.log('🚀 2210-空间站公告功能 - 接口测试');
  console.log('');
  console.log('📋 功能点覆盖清单：');
  console.log('  S1. 公告分类与权限（含多账号读写权限）');
  console.log('  S2. 编辑公告（含字段校验+已读清空+状态限制）');
  console.log('  S3. 有效期设置（设置/清除/永久）');
  console.log('  S4. 弹窗提示（弹窗/已读/多用户独立已读）');
  console.log('  S5. 发布机制（立即/定时/覆盖旧公告）');
  console.log('  S6. 当前生效管理（active/下线/重复下线）');
  console.log('  S7. 历史管理（列表/软删/状态限制/权限）');
  console.log('  S8. 横幅展示（字段精简/最多2条）');
  console.log('  S9. 公告详情（完整字段/下线后可查）');
  console.log('  + 参数校验 / 注入防护 / 异常数据 / 并发 / 响应结构 / 重复检测 / 错误码 / 未登录 / 生命周期');
  console.log('');

  try {
    await login();
    saveSession('admin');

    await test_S1_权限校验();
    await test_S2_编辑公告();
    await test_S3_有效期();
    await test_S4_弹窗();
    await test_S5_发布机制();
    await test_S6_生效管理();
    await test_S7_历史管理();
    await test_S8_横幅();
    await test_S9_详情();

    await test_参数校验();
    await test_注入防护();
    await test_异常数据();
    await test_并发();
    await test_响应结构();
    await test_重复检测();
    await test_错误码();
    await test_未登录();
    await test_生命周期();

    restoreSession('admin');
    await cleanup();
  } catch (e) {
    if (e.cause?.code === 'ECONNREFUSED') {
      console.log('\n❌ 无法连接测试环境，请检查网络');
    } else {
      console.log(`\n❌ 异常: ${e.stack || e.message}`);
    }
    try { restoreSession('admin'); await cleanup(); } catch (_) {}
    process.exit(1);
  }

  console.log(`\n=============================`);
  console.log(`✅ 通过: ${passed}  ❌ 失败: ${failed}  📊 总计: ${passed + failed}`);
  console.log(`=============================`);
  process.exit(failed > 0 ? 1 : 0);
}

main();

