    const banner = await GET(`/space-announcement/banner?spaceId=${CONFIG.spaceId}`);
    const bannerFound = banner.data?.find(a => String(a.id) === schedId);
    assert('S5.5 PENDING 不在 banner', bannerFound == null, banner.data?.map(a => String(a.id)));

    // S5.6 PENDING 公告不在 unread-popup
    const unread = await GET(`/space-announcement/unread-popup?spaceId=${CONFIG.spaceId}`);
    const unreadFound = unread.data?.find(a => String(a.id) === schedId);
    assert('S5.6 PENDING 不在 unread-popup', unreadFound == null);
  }

  // S5.7 定时发布不传 scheduledPublishTime 应报错
  const noSchedTime = await POST('/space-announcement/create', makeCreateRo({
    title: '缺定时时间', publishType: 1,
  }));
  assert('S5.7 定时发布缺时间 不报500', noSchedTime.code !== 500, noSchedTime);
}

