    [{ id: 1, title: 'x', content: '<p>x</p>' }, 'isPopup', '缺isPopup'],
    [{ id: 1, title: 'B'.repeat(101), content: '<p>x</p>', isPopup: false }, 'title', '101字符'],
  ];
  for (const [body, field, desc] of updateFields) {
