  assert('lifecycle 编辑后 isPopup=false', detail.data?.isPopup === false);

  // 4. 下线
  await offlineById(id);
  const afterOff = await GET(`/space-announcement/detail?id=${id}`);
  assert('lifecycle 下线后 status=2', afterOff.data?.status === 2);
  const activeAfter = await GET(`/space-announcement/active?category=1&spaceId=${CONFIG.spaceId}`);
  assert('lifecycle 下线后 active=null', activeAfter.data == null);
  const historyList = await GET(`/space-announcement/history?category=1&spaceId=${CONFIG.spaceId}`);
  assert('lifecycle 下线后在 history', historyList.data?.some(a => String(a.id) === id));

  // 5. 删除
  await deleteById(id);
  const historyAfter = await GET(`/space-announcement/history?category=1&spaceId=${CONFIG.spaceId}`);
  assert('lifecycle 删除后不在 history', !historyAfter.data?.some(a => String(a.id) === id));
}

