// ── 维度 4：参数校验（全面覆盖每个必填字段） ──
async function test_参数校验() {
  console.log('\n🔒 维度4: 参数校验');

  // create 接口：每个必填字段逐个测
  const fields = [
    ['title', null, 'null'],
    ['title', '', '空字符串'],
    ['content', null, 'null'],
    ['content', '', '空字符串'],
    ['category', null, 'null'],
    ['isPopup', null, 'null'],
    ['publishType', null, 'null'],
  ];
  for (const [field, value, desc] of fields) {
    const res = await POST('/space-announcement/create', makeCreateRo({ [field]: value }));
    assert(`create ${field}=${desc} 被拒绝`, res.success === false, res);
  }

  // title 边界
  const t100 = await POST('/space-announcement/create', makeCreateRo({ title: 'A'.repeat(100) }));
  assert('create title=100字符 成功', t100.success === true, t100);
  if (t100.success && t100.data?.id) cleanupIds.push(String(t100.data.id));

  const t101 = await POST('/space-announcement/create', makeCreateRo({ title: 'A'.repeat(101) }));
  assert('create title=101字符 被拒绝', t101.success === false, t101);

  // update 接口
  const updateFields = [
    [{ content: '<p>x</p>', isPopup: false }, 'id', '缺id'],
    [{ id: 1, content: '<p>x</p>', isPopup: false }, 'title', '缺title'],
    [{ id: 1, title: '', content: '<p>x</p>', isPopup: false }, 'title', '空title'],
    [{ id: 1, title: 'x', isPopup: false }, 'content', '缺content'],
    [{ id: 1, title: 'x', content: '', isPopup: false }, 'content', '空content'],
    [{ id: 1, title: 'x', content: '<p>x</p>' }, 'isPopup', '缺isPopup'],
    [{ id: 1, title: 'B'.repeat(101), content: '<p>x</p>', isPopup: false }, 'title', '101字符'],
  ];
  for (const [body, field, desc] of updateFields) {
    const res = await POST('/space-announcement/update', body);
    assert(`update ${desc} 被拒绝`, res.success === false, res);
  }

  // active 缺 category
  const noCat = await GET('/space-announcement/active?spaceId=' + CONFIG.spaceId);
  assert('active 缺 category 被拒绝', noCat.success === false || noCat.code != null, noCat);

  // pending 缺 category
  const noCatPending = await GET('/space-announcement/pending?spaceId=' + CONFIG.spaceId);
  assert('pending 缺 category 被拒绝', noCatPending.success === false || noCatPending.code != null, noCatPending);

  // history 缺 category
  const noCatHistory = await GET('/space-announcement/history?spaceId=' + CONFIG.spaceId);
  assert('history 缺 category 被拒绝', noCatHistory.success === false || noCatHistory.code != null, noCatHistory);

  // category 非法值 不报500
  const badCat = await GET(`/space-announcement/active?category=99&spaceId=${CONFIG.spaceId}`);
  assert('active category=99 不报500', badCat.code !== 500, badCat);

  // 空 body
  const emptyBody = await POST('/space-announcement/create', {});
  assert('create 空body 被拒绝', emptyBody.success === false, emptyBody);
}

