async function test_注入防护() {
  console.log('\n🛡️ 维度5: 注入防护 + 特殊字符');

  // title 特殊字符
  const specialChars = [
    '<script>alert(1)</script>',
    "' OR 1=1 --",
    '"; DROP TABLE collabspace_space_announcement;',
    '&&||',
    '🎉🎊😀',
    '<img src=x onerror=alert(1)>',
    '${7*7}',
    '{{7*7}}',
    '\'; WAITFOR DELAY \'0:0:5\' --',
  ];
  for (const ch of specialChars) {
    const res = await POST('/space-announcement/create', makeCreateRo({ title: `注入测试${ch.slice(0, 15)}` }));
    assert(`title 含 "${ch.slice(0, 20)}" 不报500`,
      res.success === true || (res.code != null && res.code !== 500), res);
    if (res.success && res.data?.id) cleanupIds.push(String(res.data.id));
  }

  // content XSS
  const xssPayloads = [
    '<img src=x onerror=alert(document.cookie)>',
    '<svg onload=alert(1)>',
    '<iframe src="javascript:alert(1)">',
    '<a href="javascript:void(0)" onclick="alert(1)">click</a>',
  ];
  for (const xss of xssPayloads) {
    const res = await POST('/space-announcement/create', makeCreateRo({ content: xss }));
    assert(`content XSS "${xss.slice(0, 25)}" 不报500`,
      res.success === true || (res.code != null && res.code !== 500), res);
    if (res.success && res.data?.id) cleanupIds.push(String(res.data.id));
  }

  // spaceId SQL 注入
  const sqlInjections = ["' OR 1=1 --", "1; DROP TABLE xxx;", "' UNION SELECT 1,2,3 --"];
  for (const inj of sqlInjections) {
    const res = await GET(`/space-announcement/banner?spaceId=${encodeURIComponent(inj)}`);
    assert(`spaceId 注入 "${inj.slice(0, 20)}" 不报500`,
      res.success === true || (res.code != null && res.code !== 500), res);
  }
}

// ── 维度 8：异常数据 ──
async function test_异常数据() {
  console.log('\n🚫 维度8: 不存在/异常数据');

  // 每个需要 ID 的接口都用不存在的合法 ID 测
  const fakeId = '1';

  const r1 = await GET(`/space-announcement/detail?id=${fakeId}`);
  assert('detail 不存在ID 不报500', r1.code !== 500, r1);

  const r2 = await POST(`/space-announcement/offline?id=${fakeId}`);
  assert('offline 不存在ID 不报500', r2.code !== 500, r2);

  const r3 = await POST(`/space-announcement/delete?id=${fakeId}`);
  assert('delete 不存在ID 不报500', r3.code !== 500, r3);

  const r4 = await POST('/space-announcement/update', {
    id: 1, title: '不存在', content: '<p>x</p>', isPopup: false,
  });
  assert('update 不存在ID 不报500', r4.code !== 500, r4);
  assert('update 不存在ID success=false', r4.success === false, r4);

  // 空 spaceId
  const r5 = await GET('/space-announcement/banner?spaceId=');
  assert('banner 空spaceId 不报500', r5.code !== 500, r5);
  const r6 = await GET('/space-announcement/unread-popup?spaceId=');
  assert('unread-popup 空spaceId 不报500', r6.code !== 500, r6);

  // 不存在的 spaceId
  const r7 = await GET('/space-announcement/active?category=1&spaceId=spcFAKE12345');
  assert('active 不存在spaceId 不报500', r7.code !== 500, r7);
  const r8 = await GET('/space-announcement/pending?category=1&spaceId=spcFAKE12345');
  assert('pending 不存在spaceId 不报500', r8.code !== 500, r8);
  const r9 = await GET('/space-announcement/history?category=1&spaceId=spcFAKE12345');
  assert('history 不存在spaceId 不报500', r9.code !== 500, r9);

  // category=2(平台)查询也正常
  const r10 = await GET(`/space-announcement/active?category=2&spaceId=${CONFIG.spaceId}`);
  assert('active category=2 不报500', r10.code !== 500, r10);
  const r11 = await GET(`/space-announcement/pending?category=2&spaceId=${CONFIG.spaceId}`);
  assert('pending category=2 不报500', r11.code !== 500, r11);
  const r12 = await GET(`/space-announcement/history?category=2&spaceId=${CONFIG.spaceId}`);
  assert('history category=2 不报500', r12.code !== 500, r12);
}

// ── 维度 9：并发请求 ──
async function test_并发() {
  console.log('\n🔀 维度9: 并发请求');

  const promises = Array.from({ length: 10 }, () =>
    GET(`/space-announcement/banner?spaceId=${CONFIG.spaceId}`)
  );
  const results = await Promise.all(promises);
  assert('10个并发 banner 都成功', results.every(r => r.success === true), results.map(r => r.success));

  const promises2 = Array.from({ length: 10 }, () =>
    GET(`/space-announcement/active?category=1&spaceId=${CONFIG.spaceId}`)
  );
  const results2 = await Promise.all(promises2);
  assert('10个并发 active 都成功', results2.every(r => r.success === true));

  const promises3 = Array.from({ length: 5 }, () =>
    GET(`/space-announcement/unread-popup?spaceId=${CONFIG.spaceId}`)
  );
  const results3 = await Promise.all(promises3);
  assert('5个并发 unread-popup 都成功', results3.every(r => r.success === true));
}

// ── 维度 10：响应结构 ──
async function test_响应结构() {
  console.log('\n📦 维度10: 响应结构一致性');

  const pending = await GET(`/space-announcement/pending?category=1&spaceId=${CONFIG.spaceId}`);
  assert('pending success=true', pending.success === true);
  assert('pending data 是数组', Array.isArray(pending.data));

  const history = await GET(`/space-announcement/history?category=1&spaceId=${CONFIG.spaceId}`);
  assert('history success=true', history.success === true);
  assert('history data 是数组', Array.isArray(history.data));

  const banner = await GET(`/space-announcement/banner?spaceId=${CONFIG.spaceId}`);
  assert('banner success=true', banner.success === true);
  assert('banner data 是数组', Array.isArray(banner.data));

  const unread = await GET(`/space-announcement/unread-popup?spaceId=${CONFIG.spaceId}`);
  assert('unread-popup success=true', unread.success === true);
  assert('unread-popup data 是数组', Array.isArray(unread.data));

  const active = await GET(`/space-announcement/active?category=1&spaceId=${CONFIG.spaceId}`);
  assert('active success=true', active.success === true);
  // active data 可以是 null 或 object
  assert('active data 是 null 或 object', active.data == null || typeof active.data === 'object', typeof active.data);
}

// ── 维度 12：数据重复检测 ──
async function test_重复检测() {
  console.log('\n🐛 维度12: 数据重复检测');

  // 连续创建3条 → 只有最后一条 ACTIVE
  const id1 = await createAndGetId({ title: '重复检测-1' });
  const id2 = await createAndGetId({ title: '重复检测-2' });
  const id3 = await createAndGetId({ title: '重复检测-3' });
  if (id1) cleanupIds.push(id1);
  if (id2) cleanupIds.push(id2);
  if (id3) cleanupIds.push(id3);

  const active = await GET(`/space-announcement/active?category=1&spaceId=${CONFIG.spaceId}`);
  assert('连续3条只有最后1条ACTIVE', active.data != null && String(active.data.id) === id3, active.data?.id);

  if (id1) {
    const d1 = await GET(`/space-announcement/detail?id=${id1}`);
    assert('第1条被下线(status=2)', d1.data?.status === 2, d1.data?.status);
  }
  if (id2) {
    const d2 = await GET(`/space-announcement/detail?id=${id2}`);
    assert('第2条被下线(status=2)', d2.data?.status === 2, d2.data?.status);
  }

  // 重复查看详情（已读记录幂等）
  if (id3) {
    for (let i = 0; i < 5; i++) {
      const res = await GET(`/space-announcement/detail?id=${id3}`);
      if (i === 4) assert('5次重复查看详情不报错', res.success === true || res.code !== 500, res);
    }
  }
}

// ── 维度 13：错误码规范 ──
