// ── 完整生命周期测试 ──
async function test_生命周期() {
  console.log('\n🔄 完整生命周期：创建→编辑→下线→删除');

  // 1. 创建
  const createRes = await POST('/space-announcement/create', makeCreateRo({
    title: '生命周期测试', content: '<p>初始内容</p>', isPopup: true, expireTime: futureTime(60),
  }));
  assert('lifecycle 创建成功', createRes.success === true, createRes);
  const id = createRes.success ? String(createRes.data?.id) : null;
  if (!id) return;

  // 2. 验证在各列表中
  const active = await GET(`/space-announcement/active?category=1&spaceId=${CONFIG.spaceId}`);
  assert('lifecycle ACTIVE 状态 active 有数据', active.data != null && String(active.data.id) === id);
  const banner = await GET(`/space-announcement/banner?spaceId=${CONFIG.spaceId}`);
  assert('lifecycle ACTIVE 在 banner', banner.data?.some(a => String(a.id) === id));
  const unread = await GET(`/space-announcement/unread-popup?spaceId=${CONFIG.spaceId}`);
  assert('lifecycle ACTIVE+popup 在 unread', unread.data?.some(a => String(a.id) === id));

  // 3. 编辑
  await POST('/space-announcement/update', {
    id: id, title: '生命周期-已编辑', content: '<p>编辑后</p>', isPopup: false,
  });
  const detail = await GET(`/space-announcement/detail?id=${id}`);
  assert('lifecycle 编辑后标题正确', detail.data?.title === '生命周期-已编辑');
  assert('lifecycle 编辑后 isPopup=false', detail.data?.isPopup === false);

  // 4. 下线
  await offlineById(id);
  const afterOff = await GET(`/space-announcement/detail?id=${id}`);
  assert('lifecycle 下线后 status=2', afterOff.data?.status === 2);
  const activeAfter = await GET(`/space-announcement/active?category=1&spaceId=${CONFIG.spaceId}`);
  assert('lifecycle 下线后 active=null', activeAfter.data == null);
  const historyList = await GET(`/space-announcement/history?category=1&spaceId=${CONFIG.spaceId}`);
  assert('lifecycle 下线后在 history', historyList.data?.some(a => String(a.id) === id));

  // 5. 删除
  await deleteById(id);
  const historyAfter = await GET(`/space-announcement/history?category=1&spaceId=${CONFIG.spaceId}`);
  assert('lifecycle 删除后不在 history', !historyAfter.data?.some(a => String(a.id) === id));
}

// ========== 清理 ==========
async function cleanup() {
  console.log('\n🧹 清理测试数据...');
  let cleaned = 0;
  for (const id of cleanupIds) {
    try {
      await offlineById(id);
      await deleteById(id);
      cleaned++;
    } catch (e) { /* ignore */ }
  }
  console.log(`   清理了 ${cleaned} 条公告`);
}

// ========== 执行 ==========
async function main() {
  console.log('🚀 2210-空间站公告功能 - 接口测试');
  console.log('');
  console.log('📋 功能点覆盖清单：');
  console.log('  S1. 公告分类与权限（含多账号读写权限）');
  console.log('  S2. 编辑公告（含字段校验+已读清空+状态限制）');
  console.log('  S3. 有效期设置（设置/清除/永久）');
  console.log('  S4. 弹窗提示（弹窗/已读/多用户独立已读）');
  console.log('  S5. 发布机制（立即/定时/覆盖旧公告）');
  console.log('  S6. 当前生效管理（active/下线/重复下线）');
  console.log('  S7. 历史管理（列表/软删/状态限制/权限）');
  console.log('  S8. 横幅展示（字段精简/最多2条）');
  console.log('  S9. 公告详情（完整字段/下线后可查）');
  console.log('  + 参数校验 / 注入防护 / 异常数据 / 并发 / 响应结构 / 重复检测 / 错误码 / 未登录 / 生命周期');
  console.log('');

  try {
    await login();
    saveSession('admin');

    await test_S1_权限校验();
    await test_S2_编辑公告();
    await test_S3_有效期();
    await test_S4_弹窗();
    await test_S5_发布机制();
    await test_S6_生效管理();
    await test_S7_历史管理();
    await test_S8_横幅();
    await test_S9_详情();

    await test_参数校验();
    await test_注入防护();
    await test_异常数据();
    await test_并发();
    await test_响应结构();
    await test_重复检测();
    await test_错误码();
    await test_未登录();
    await test_生命周期();

    restoreSession('admin');
    await cleanup();
  } catch (e) {
    if (e.cause?.code === 'ECONNREFUSED') {
      console.log('\n❌ 无法连接测试环境，请检查网络');
    } else {
      console.log(`\n❌ 异常: ${e.stack || e.message}`);
    }
    try { restoreSession('admin'); await cleanup(); } catch (_) {}
    process.exit(1);
  }

  console.log(`\n=============================`);
  console.log(`✅ 通过: ${passed}  ❌ 失败: ${failed}  📊 总计: ${passed + failed}`);
  console.log(`=============================`);
  process.exit(failed > 0 ? 1 : 0);
}

main();

