  assert('S6.1 active 返回成功', active.success === true, active);
  assert('S6.1 data 非 null', active.data != null, active.data);
  if (active.data) {
    assert('S6.1 含 id', active.data.id != null);
    assert('S6.1 含 title(string)', typeof active.data.title === 'string');
    assert('S6.1 含 content(string)', typeof active.data.content === 'string');
