// ── 维度 5：注入防护 ──
async function test_注入防护() {
  console.log('\n🛡️ 维度5: 注入防护 + 特殊字符');

  // title 特殊字符
  const specialChars = [
    '<script>alert(1)</script>',
    "' OR 1=1 --",
    '"; DROP TABLE collabspace_space_announcement;',
    '&&||',
    '🎉🎊😀',
    '<img src=x onerror=alert(1)>',
    '${7*7}',
    '{{7*7}}',
    '\'; WAITFOR DELAY \'0:0:5\' --',
  ];
  for (const ch of specialChars) {
    const res = await POST('/space-announcement/create', makeCreateRo({ title: `注入测试${ch.slice(0, 15)}` }));
    assert(`title 含 "${ch.slice(0, 20)}" 不报500`,
      res.success === true || (res.code != null && res.code !== 500), res);
    if (res.success && res.data?.id) cleanupIds.push(String(res.data.id));
  }

  // content XSS
  const xssPayloads = [
    '<img src=x onerror=alert(document.cookie)>',
    '<svg onload=alert(1)>',
    '<iframe src="javascript:alert(1)">',
    '<a href="javascript:void(0)" onclick="alert(1)">click</a>',
  ];
  for (const xss of xssPayloads) {
    const res = await POST('/space-announcement/create', makeCreateRo({ content: xss }));
    assert(`content XSS "${xss.slice(0, 25)}" 不报500`,
      res.success === true || (res.code != null && res.code !== 500), res);
    if (res.success && res.data?.id) cleanupIds.push(String(res.data.id));
  }

  // spaceId SQL 注入
  const sqlInjections = ["' OR 1=1 --", "1; DROP TABLE xxx;", "' UNION SELECT 1,2,3 --"];
  for (const inj of sqlInjections) {
    const res = await GET(`/space-announcement/banner?spaceId=${encodeURIComponent(inj)}`);
    assert(`spaceId 注入 "${inj.slice(0, 20)}" 不报500`,
      res.success === true || (res.code != null && res.code !== 500), res);
  }
}

